@app.route("/database")
@admin_required
def database():
    # No-cache so a fresh deploy's renderTable / saveStudentCell / etc.
    # land in the browser immediately. Without this, browsers happily
    # serve the previously-cached page (which still has the old toggle-
    # edit pattern) and editable cells appear "stuck" until the user
    # hard-refreshes — visible as "only attendance and taqseet are
    # directly editable" while the rest still look read-only.
    resp = Response(DATABASE_HTML.replace("USER_ROLE_PLACEHOLDER", "admin"), mimetype='text/html; charset=utf-8')
    resp.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate, max-age=0'
    resp.headers['Pragma'] = 'no-cache'
    return resp


# ─── Parent portal (public, no login) ──────────────────────────────
# Rate-limit: 10 lookups per IP per hour. The store is process-local
# so under multi-worker gunicorn each worker tracks its own counter
# (acceptable for soft limiting; harden with Redis if abuse seen).
import threading as _threading
_PARENT_RATE = {}        # ip -> [timestamps]
_PARENT_RATE_LOCK = _threading.Lock()
_PARENT_RATE_WINDOW = 3600
_PARENT_RATE_MAX = 10

def _parent_rate_check(ip):
    """Rate-limit was removed at the team's request — parents who
    mistype the personal_id were getting locked out for an hour
    and missing time-sensitive payment / attendance info. Function
    kept as a no-op so existing call sites compile unchanged. The
    in-memory dict is also cleared on import below so currently-
    locked IPs can hit the parent portal immediately on the next
    deploy."""
    return True


# Clear any in-memory locks left over from previous server lifetime —
# safe to do at module import since the dicts are process-local.
# Parents/staff currently sitting on a "too many attempts" error get
# immediate access on the next request after this code deploys.
try:
    _LOGIN_FAILS.clear()
except Exception:
    pass
try:
    with _PARENT_RATE_LOCK:
        _PARENT_RATE.clear()
except Exception:
    pass

