# --- Unified Table Management (works for all tables) ---------------------

# Maps a frontend table key to (db_table_name, labels_table_name_or_None).
# Also accepts numeric ids for entries in custom_tables.
_TABLE_MAP = {
    "students":       ("students",        "column_labels"),
    "groups":         ("student_groups",  "group_col_labels"),
    "student_groups": ("student_groups",  "group_col_labels"),
    "attendance":     ("attendance",      "att_col_labels"),
    "evaluations":    ("evaluations",     "eval_col_labels"),
    "evals":          ("evaluations",     "eval_col_labels"),
    "payment_log":    ("payment_log",     "paylog_col_labels"),
    "paylog":         ("payment_log",     "paylog_col_labels"),
    "taqseet":        ("taqseet",         "taqseet_col_labels"),
}

def _resolve_table(tid):
    """Return (db_table, labels_table) for a table identifier.

    tid can be either a built-in table key (e.g. 'students', 'payment_log')
    or a stringified numeric id that points at a row in custom_tables.
    Returns (None, None) if not found.
    """
    tid_str = str(tid or "").strip()
    if tid_str.isdigit():
        db = get_db()
        try:
            row = db.execute("SELECT tbl_name FROM custom_tables WHERE id=?", (int(tid_str),)).fetchone()
            if row:
                return (row[0], None)
        except Exception:
            return (None, None)
        return (None, None)
    return _TABLE_MAP.get(tid_str, (None, None))


def _is_safe_ident(s):
    import re as _re
    return bool(s and _re.match(r'^[A-Za-z_][A-Za-z0-9_]{0,63}$', s))


# ─── Dynamic Configuration System ─────────────────────────────────────────
# Reads settings rows to remap table/column references across the app.
# Never raises — falls back to the caller-provided default if the settings
# row is missing or the DB is in an incomplete state.
def get_setting(page, component, default=''):
    try:
        db = get_db()
        row = db.execute(
            "SELECT value FROM settings WHERE page=? AND component=?",
            (page, component),
        ).fetchone()
        if row is None:
            return default
        v = row[0] if hasattr(row, '__getitem__') else None
        if v is None or v == '':
            return default
        return v
    except Exception:
        return default


def get_all_tables():
    """List every user-visible table in the live DB."""
    try:
        db = get_db()
        if USE_PG:
            rows = db.execute(
                "SELECT table_name FROM information_schema.tables "
                "WHERE table_schema='public' AND table_type='BASE TABLE' "
                "ORDER BY table_name"
            ).fetchall()
        else:
            rows = db.execute(
                "SELECT name FROM sqlite_master WHERE type='table' "
                "AND name NOT LIKE 'sqlite_%' ORDER BY name"
            ).fetchall()
        return [r[0] for r in rows]
    except Exception:
        return []


def get_table_columns(table_name):
    """List every column in the given table. Safe-name validated."""
    if not _is_safe_ident(table_name):
        return []
    try:
        db = get_db()
        rows = db.execute("PRAGMA table_info(" + table_name + ")").fetchall()
        return [r[1] for r in rows]
    except Exception:
        return []


_BACKUP_DIR = None
def _backup_dir():
    """Resolve a writable directory for backup files. /tmp is the
    standard ephemeral location on Render — files survive the dyno
    lifetime, which is enough for users to download or for the
    auto-email path to attach them. Admins can mirror to durable
    storage by changing BACKUP_DIR env."""
    global _BACKUP_DIR
    if _BACKUP_DIR: return _BACKUP_DIR
    import os as _os, tempfile
    p = _os.environ.get("BACKUP_DIR") or _os.path.join(tempfile.gettempdir(), "mindex_backups")
    try: _os.makedirs(p, exist_ok=True)
    except Exception: pass
    _BACKUP_DIR = p
    return p


def _backup_arabic_table_name(internal):
    """Best-effort Arabic display name for a table — used as the
    sheet name in the Excel export. Falls back to the internal name."""
    try:
        return _table_display_label(internal) or internal
    except Exception:
        return internal


def _backup_arabic_col_name(table, internal):
    try:
        cmap = _column_label_map(table) or {}
        return cmap.get(internal, internal)
    except Exception:
        return internal


def _backup_collect_tables(db):
    """List every public/sqlite table the backup should include."""
    try:
        if USE_PG:
            rows = db.execute(
                "SELECT table_name FROM information_schema.tables "
                "WHERE table_schema=\'public\' AND table_type=\'BASE TABLE\' "
                "ORDER BY table_name"
            ).fetchall()
        else:
            rows = db.execute(
                "SELECT name FROM sqlite_master WHERE type=\'table\' "
                "AND name NOT LIKE \'sqlite_%\' ORDER BY name"
            ).fetchall()
        return [r[0] for r in rows]
    except Exception:
        return []


def _backup_table_columns(db, t):
    try:
        return [r[1] for r in db.execute("PRAGMA table_info(" + t + ")").fetchall()]
    except Exception:
        return []


# Sheet ordering — matches the قاعدة البيانات UI sidebar. Tables not
# in this list come after, sorted alphabetically.
_BACKUP_SHEET_ORDER = [
    "students", "student_groups", "attendance", "payment_log",
    "taqseet", "student_payments", "evaluations", "receipts_log",
    "session_durations", "parent_receipts", "payment_edits",
    "custom_tables", "custom_table_cols", "custom_table_rows",
    # Feature tables next (points + messaging + center mode + backup)
    "behaviors", "point_events", "point_notifications",
    "rewards", "redemptions", "avatars", "levels",
    "message_templates", "message_log", "message_reminders",
    "payment_messages", "mode_exceptions", "backup_log",
    # System tables last
    "users", "settings", "schema_migrations", "table_labels",
    "column_labels", "group_col_labels", "att_col_labels",
    "eval_col_labels", "taqseet_col_labels", "paylog_col_labels",
]


def _backup_ordered_tables(db):
    """Return tables in the canonical UI order, with any unlisted
    tables appended alphabetically at the end."""
    all_tables = _backup_collect_tables(db)
    seen = set()
    out = []
    for t in _BACKUP_SHEET_ORDER:
        if t in all_tables:
            out.append(t); seen.add(t)
    for t in sorted(all_tables):
        if t not in seen:
            out.append(t)
    return out


# Date and currency-like column heuristics for cell formatting.
_DATE_COL_HINTS = (
    "date", "_at", "due_", "issued_at", "redeemed_at", "delivered_at",
    "downloaded_at", "created_at", "sent_at", "applied_at",
    "reviewed_at", "upload_date", "form_fill_date", "edit_date",
    "attendance_date",
)
_CURRENCY_COL_HINTS = (
    "amount", "course_amount", "total_paid", "total_remaining",
    "installment", "paid_amount", "points_spent", "bytes_written",
    "size_bytes",
)
_BOOLEAN_COL_HINTS = (
    "is_active", "is_global", "must_change_pw", "is_visible",
    "books_received",
)


def _backup_format_cell_value(col_name, v):
    """Return (display_value, number_format) tuple for an openpyxl
    cell. None → empty cell, dates → ISO-style, booleans → نعم/لا,
    currencies use the د.ب suffix in number_format."""
    if v is None or v == "":
        return "", None
    cn = (col_name or "").lower()
    # Booleans first — only on canonical-named columns to avoid
    # turning e.g. installment_number into نعم/لا.
    if cn in _BOOLEAN_COL_HINTS or cn.startswith("is_"):
        if isinstance(v, (int, bool)):
            return ("نعم" if int(v) else "لا"), None
        sv = str(v).strip().lower()
        if sv in ("1", "true", "yes", "y", "نعم"): return "نعم", None
        if sv in ("0", "false", "no", "n", "لا"):  return "لا", None
    # Date-shaped columns
    if any(h in cn for h in _DATE_COL_HINTS):
        s = str(v).strip()
        # Don't munge non-date contents; show as-is. Excel auto-renders
        # ISO yyyy-mm-dd in date format anyway.
        return s, None
    # Currency-shaped columns
    if cn in _CURRENCY_COL_HINTS or cn.endswith("_amount"):
        if isinstance(v, (int, float)):
            try:
                return float(v), '#,##0.000" د.ب"'
            except Exception:
                pass
        return str(v), None
    # Numeric pass-through
    if isinstance(v, (int, float)):
        return v, None
    return str(v), None


def _backup_build_excel(db, audit_trace=None):
    """Publication-quality Excel export. Returns (bytes, per_table_counts).

    audit_trace, if a list, gets per-table dicts appended for the
    multi-stage verification flow.
    """
    import io as _io
    try:
        from openpyxl import Workbook
        from openpyxl.styles import Font, Alignment, PatternFill
        from openpyxl.utils import get_column_letter
    except Exception as ex:
        raise RuntimeError("openpyxl not available: " + str(ex))

    wb = Workbook()
    wb.remove(wb.active)

    used_titles = set()
    def _safe_title(name, maxlen=31):
        t = (name or "table")
        for ch in "[]:*?/\\":
            t = t.replace(ch, "_")
        t = t[:maxlen] or "table"
        base = t; i = 2
        while t in used_titles:
            suf = "_" + str(i)
            t = (base[: maxlen - len(suf)] + suf)
            i += 1
        used_titles.add(t)
        return t

    # Style toolkit.
    HEADER_FILL = PatternFill("solid", fgColor="7F77DD")
    ZEBRA_FILL  = PatternFill("solid", fgColor="F8F8F8")
    HEADER_FONT = Font(name="Arial", size=11, bold=True, color="FFFFFF")
    BODY_FONT   = Font(name="Arial", size=11)
    HEADER_ALIGN = Alignment(horizontal="center", vertical="center",
                             wrap_text=True, readingOrder=2)
    RTL_ALIGN   = Alignment(horizontal="right", vertical="center",
                            wrap_text=True, readingOrder=2)
    NUM_ALIGN   = Alignment(horizontal="left", vertical="center", readingOrder=2)

    # Build INDEX sheet first; we fill it after we know the per-sheet
    # counts. Reserve it now so it's the first tab.
    idx_ws = wb.create_sheet(_safe_title("الفهرس"))
    try: idx_ws.sheet_view.rightToLeft = True
    except Exception: pass

    per_table_counts = []   # [{table, sheet, db_count, written, columns}]
    grand_total = 0

    for t in _backup_ordered_tables(db):
        cols = _backup_table_columns(db, t)
        if not cols:
            continue
        sheet_name = _safe_title(_backup_arabic_table_name(t))
        ws = wb.create_sheet(sheet_name)
        try: ws.sheet_view.rightToLeft = True
        except Exception: pass
        ws.row_dimensions[1].height = 25
        labels = [_backup_arabic_col_name(t, c) for c in cols]

        # Header row
        for j, lbl in enumerate(labels, start=1):
            cell = ws.cell(row=1, column=j, value=str(lbl))
            cell.font = HEADER_FONT
            cell.fill = HEADER_FILL
            cell.alignment = HEADER_ALIGN

        # STAGE 1: count expected rows from DB.
        try:
            db_count = int(db.execute(
                "SELECT COUNT(*) FROM " + '"' + t + '"'
            ).fetchone()[0] or 0)
        except Exception:
            db_count = 0

        # Pull rows.
        try:
            data = db.execute(
                "SELECT " + ",".join('"' + c + '"' for c in cols) +
                " FROM " + '"' + t + '"'
            ).fetchall()
        except Exception:
            data = []

        # STAGE 2: write rows to sheet, counting as we go. Track the
        # widest content per column for auto-fit.
        max_widths = [len(str(lbl or "")) + 4 for lbl in labels]
        written = 0
        for ri, row in enumerate(data, start=2):
            try:
                vals = list(row) if not hasattr(row, "keys") else [row[k] for k in cols]
            except Exception:
                vals = list(row) if hasattr(row, "__iter__") else []
            zebra = (ri % 2 == 1)   # rows 3, 5, 7, ... → light gray
            for j, v in enumerate(vals, start=1):
                disp, fmt = _backup_format_cell_value(cols[j-1], v)
                cell = ws.cell(row=ri, column=j, value=disp)
                cell.font = BODY_FONT
                if isinstance(disp, (int, float)) and not isinstance(disp, bool):
                    cell.alignment = NUM_ALIGN
                else:
                    cell.alignment = RTL_ALIGN
                if fmt:
                    try: cell.number_format = fmt
                    except Exception: pass
                if zebra:
                    cell.fill = ZEBRA_FILL
                w = len(str(disp))
                if w > max_widths[j-1]:
                    max_widths[j-1] = w
            written += 1

        ws.freeze_panes = "A2"
        # Auto-fit (clamped 10..50).
        for j in range(1, len(cols) + 1):
            try:
                col_letter = get_column_letter(j)
                ws.column_dimensions[col_letter].width = max(10, min(50, max_widths[j-1] + 2))
            except Exception:
                pass

        per_table_counts.append({
            "table":      t,
            "sheet":      sheet_name,
            "db_count":   db_count,
            "written":    written,
            "columns":    len(cols),
        })
        grand_total += written
        if isinstance(audit_trace, list):
            audit_trace.append({"stage": "write", "table": t,
                                "db_count": db_count, "written": written})

    # Fill the INDEX sheet now that we have all the per-sheet counts.
    try:
        idx_ws.row_dimensions[1].height = 30
        idx_ws.cell(row=1, column=1, value="الفهرس — نسخة احتياطية مايندكس").font = Font(name="Arial", size=14, bold=True, color="4A148C")
        idx_ws.cell(row=2, column=1, value="إجمالي عدد الصفوف في هذه النسخة: " + str(grand_total)).font = Font(name="Arial", size=11, bold=True)
        idx_ws.cell(row=3, column=1, value="تم التوليد: " + __import__("datetime").datetime.now().strftime("%Y-%m-%d %H:%M:%S")).font = BODY_FONT
        # Header row at row 5
        hdrs = ["اسم الورقة", "الجدول الخام", "عدد الصفوف", "عدد الأعمدة", "الانتقال"]
        for j, h in enumerate(hdrs, start=1):
            cell = idx_ws.cell(row=5, column=j, value=h)
            cell.font = HEADER_FONT; cell.fill = HEADER_FILL; cell.alignment = HEADER_ALIGN
        for i, info in enumerate(per_table_counts, start=6):
            idx_ws.cell(row=i, column=1, value=info["sheet"]).alignment = RTL_ALIGN
            idx_ws.cell(row=i, column=2, value=info["table"]).alignment = NUM_ALIGN
            idx_ws.cell(row=i, column=3, value=info["written"]).alignment = NUM_ALIGN
            idx_ws.cell(row=i, column=4, value=info["columns"]).alignment = NUM_ALIGN
            link_cell = idx_ws.cell(row=i, column=5, value="انتقل إلى الورقة")
            try:
                # Hyperlink to the sheet's A1.
                link_cell.hyperlink = "#'" + info["sheet"] + "'!A1"
                link_cell.font = Font(name="Arial", size=11, color="1565C0", underline="single")
            except Exception:
                pass
            link_cell.alignment = RTL_ALIGN
            for j in range(1, 6):
                if (i % 2 == 0):
                    idx_ws.cell(row=i, column=j).fill = ZEBRA_FILL
        idx_ws.freeze_panes = "A6"
        for j, w in enumerate([28, 22, 12, 12, 22], start=1):
            try: idx_ws.column_dimensions[get_column_letter(j)].width = w
            except Exception: pass
    except Exception as _ex:
        import sys as _sys
        print("[backup] index sheet build failed: " + str(_ex), file=_sys.stderr)

    buf = _io.BytesIO()
    wb.save(buf)
    return buf.getvalue(), per_table_counts


def _backup_build_sql(db):
    """SQL-style dump with CREATE TABLE-like comments + INSERT
    statements. Round-trippable on SQLite + readable on Postgres."""
    import datetime as _dt
    out = []
    out.append("-- Mindex backup SQL dump")
    out.append("-- generated: " + _dt.datetime.utcnow().strftime("%Y-%m-%d %H:%M:%S UTC"))
    out.append("")
    for t in _backup_collect_tables(db):
        cols = _backup_table_columns(db, t)
        if not cols: continue
        try:
            rows = db.execute("SELECT " + ",".join("\"" + c + "\"" for c in cols) + " FROM " + t).fetchall()
        except Exception:
            rows = []
        out.append("-- ── " + t + " (" + str(len(rows)) + " rows) ──")
        out.append("-- columns: " + ", ".join(cols))
        for r in rows:
            try:
                vals = list(r) if not hasattr(r, "keys") else [r[k] for k in cols]
            except Exception:
                vals = list(r) if hasattr(r, "__iter__") else []
            parts = []
            for v in vals:
                if v is None:                     parts.append("NULL")
                elif isinstance(v, (int, float)): parts.append(str(v))
                else:                              parts.append("\'" + str(v).replace("\'", "\'\'") + "\'")
            out.append("INSERT INTO \"" + t + "\" (" + ",".join("\"" + c + "\"" for c in cols) +
                       ") VALUES (" + ",".join(parts) + ");")
        out.append("")
    return "\n".join(out).encode("utf-8")


def _backup_send_email(zip_path, recipients, settings_kind):
    """Best-effort SMTP send. Reads SMTP_HOST / SMTP_USER / SMTP_PASS
    / SMTP_FROM env. Returns (status_str, error_str)."""
    import os as _os
    if not recipients:
        return "skipped", "no recipients configured"
    host = _os.environ.get("SMTP_HOST") or ""
    if not host:
        return "skipped", "SMTP_HOST not set"
    user = _os.environ.get("SMTP_USER") or ""
    pwd  = _os.environ.get("SMTP_PASS") or ""
    sender = _os.environ.get("SMTP_FROM") or user or "mindx-backups@localhost"
    try:
        import smtplib, ssl
        from email.mime.multipart import MIMEMultipart
        from email.mime.base import MIMEBase
        from email.mime.text import MIMEText
        from email import encoders
        msg = MIMEMultipart()
        msg["From"] = sender
        msg["To"]   = ", ".join(recipients)
        msg["Subject"] = "Mindex backup (" + settings_kind + ")"
        msg.attach(MIMEText("نسخة احتياطية تلقائية - مرفقة بصيغة ZIP.", "plain", "utf-8"))
        with open(zip_path, "rb") as f:
            part = MIMEBase("application", "zip")
            part.set_payload(f.read())
        encoders.encode_base64(part)
        part.add_header("Content-Disposition", "attachment",
                        filename=_os.path.basename(zip_path))
        msg.attach(part)
        port = int(_os.environ.get("SMTP_PORT") or 587)
        ctx = ssl.create_default_context()
        with smtplib.SMTP(host, port, timeout=20) as s:
            try: s.starttls(context=ctx)
            except Exception: pass
            if user and pwd: s.login(user, pwd)
            s.sendmail(sender, recipients, msg.as_string())
        return "sent", ""
    except Exception as ex:
        return "failed", str(ex)


def _backup_reopen_count(excel_bytes):
    """STAGE 3: re-open the generated Excel buffer and count rows on
    each sheet (excluding the index sheet + header row). Returns
    {sheet_name: data_row_count}."""
    import io as _io
    try:
        from openpyxl import load_workbook
    except Exception:
        return {}
    try:
        wb = load_workbook(_io.BytesIO(excel_bytes), read_only=True)
    except Exception:
        return {}
    out = {}
    for ws in wb.worksheets:
        if ws.title == "الفهرس": continue
        # max_row counts the highest row with data; the header is at
        # row 1 so data rows = max_row - 1 (clamped to 0).
        try:
            mr = ws.max_row or 0
        except Exception:
            mr = 0
        out[ws.title] = max(0, mr - 1)
    try: wb.close()
    except Exception: pass
    return out


def _backup_sql_count_rows(sql_text):
    """STAGE 3 (SQL leg): count INSERT statements per table in the
    generated SQL dump. Used as a third independent check."""
    counts = {}
    import re as _re
    for m in _re.finditer(r'INSERT INTO "([^"]+)"', sql_text):
        t = m.group(1)
        counts[t] = counts.get(t, 0) + 1
    return counts


def _backup_compose_verification_report(meta, per_table, sql_counts,
                                        reopen_counts_by_sheet,
                                        fingerprints):
    """Compose the Arabic verification report. Returns a UTF-8 string
    (BOM is added when written to file)."""
    L = []
    L.append("════════════════════════════════════════════════════════")
    L.append("           تقرير التحقق من النسخة الاحتياطية")
    L.append("════════════════════════════════════════════════════════")
    L.append("")
    L.append("اسم الملف:      " + meta.get("zip_name", ""))
    L.append("تاريخ التوليد:  " + meta.get("ts", ""))
    L.append("منشئ النسخة:    " + meta.get("user", ""))
    L.append("النوع:           " + meta.get("kind", ""))
    if meta.get("reason"):
        L.append("السبب:          " + meta.get("reason", ""))
    L.append("قاعدة البيانات: " + meta.get("db_kind", ""))
    L.append("")
    L.append("بصمات الملفات (SHA-256):")
    for k, v in (fingerprints or {}).items():
        L.append("  " + k.ljust(28) + " " + v)
    L.append("")
    total_rows = sum(int(t.get("written") or 0) for t in per_table)
    L.append("ملخص النسخة:")
    L.append("  عدد الجداول المُصدَّرة: " + str(len(per_table)))
    L.append("  إجمالي الصفوف:          " + str(total_rows))
    L.append("")
    L.append("التحقق من المطابقة لكل جدول")
    L.append("(قاعدة البيانات ↔ Excel ↔ SQL)")
    L.append("─" * 60)
    header = ("الجدول".ljust(26) +
              "DB".rjust(8) +
              "Excel".rjust(10) +
              "SQL".rjust(8) +
              "الحالة".rjust(12))
    L.append(header)
    L.append("─" * 60)
    all_ok = True
    for t in per_table:
        dbn = int(t.get("db_count") or 0)
        wrn = int(t.get("written") or 0)
        sql = int(sql_counts.get(t.get("table"), 0))
        xls = int(reopen_counts_by_sheet.get(t.get("sheet"), wrn))
        match = (dbn == wrn == sql == xls)
        if not match: all_ok = False
        status = "✓ مطابق" if match else "✗ مختلف"
        line = (str(t.get("table") or "")[:24].ljust(26) +
                str(dbn).rjust(8) +
                str(xls).rjust(10) +
                str(sql).rjust(8) +
                status.rjust(12))
        L.append(line)
    L.append("─" * 60)
    L.append("")
    L.append("نتيجة التحقق العامة: " + ("✅ نجح التحقق — جميع الأعداد متطابقة"
                                          if all_ok else "❌ فشل التحقق — اختلاف في الأعداد"))
    L.append("")
    L.append("ملاحظات:")
    L.append("  • DB    = عدد الصفوف المقروء من قاعدة البيانات قبل الكتابة (Stage 1).")
    L.append("  • Excel = عدد الصفوف عند إعادة فتح ملف Excel وقراءته (Stage 3).")
    L.append("  • SQL   = عدد جمل INSERT المحفوظة في ملف SQL (Stage 3).")
    L.append("  • التحقق آلي ولحظي. أي اختلاف يلغي حفظ الملف لحماية البيانات.")
    L.append("")
    L.append("لاستعادة هذه النسخة:")
    L.append("  1. فك ضغط الملف .zip")
    L.append("  2. افتح ملف Excel وراجع تبويب «الفهرس» للتأكد من الجداول.")
    L.append("  3. لاستعادة قاعدة البيانات استخدم ملف SQL في sqlite3/psql.")
    L.append("")
    return "\n".join(L) + "\n"


def _create_full_backup(db, kind="manual", reason=""):
    """Generate Excel + SQL with multi-stage row-count verification.
    Bundles Excel + SQL + VERIFICATION_REPORT.txt + (optional) CLAUDE.md
    + TABLE_AUDIT.md into a *_verified.zip. Aborts (no file written)
    on any row-count mismatch.

    Returns dict with id/filename/path/size_bytes/kind/reason/
    email_status/email_error/tables_count/total_rows/verified/
    report_text/mismatch (the last is non-empty on abort)."""
    import zipfile, os as _os, datetime as _dt, hashlib as _hashlib

    bdir = _backup_dir()
    stamp = _dt.datetime.now().strftime("%Y-%m-%d_%H-%M")
    zip_name  = "mindex_backup_" + stamp + "_verified.zip"
    zip_path  = _os.path.join(bdir, zip_name)
    xlsx_name = "mindex_backup_" + stamp + ".xlsx"
    sql_name  = "mindex_backup_" + stamp + ".sql"

    # Progress tracking — published via /api/backup/progress so the UI
    # can poll. Best-effort; if anything throws, the export still runs.
    def _publish(stage, msg, **extra):
        try:
            payload = {"stage": stage, "msg": msg, "ts":
                       _dt.datetime.now().strftime("%H:%M:%S")}
            payload.update(extra)
            _BACKUP_PROGRESS.update(payload)
        except Exception:
            pass

    _publish("start", "بدء العملية", percent=2)

    # ── STAGE 1+2: Build Excel (counts during write) ──
    _publish("excel", "كتابة Excel...", percent=15)
    try:
        excel_bytes, per_table = _backup_build_excel(db)
    except Exception as ex:
        _publish("error", "فشل بناء Excel: " + str(ex), percent=0)
        raise

    # ── Build SQL ──
    _publish("sql", "كتابة SQL...", percent=45)
    sql_bytes = _backup_build_sql(db)

    # ── STAGE 3: re-open Excel + count rows; count SQL inserts ──
    _publish("verify", "التحقق من المطابقة...", percent=70)
    reopen_counts = _backup_reopen_count(excel_bytes)
    try:
        sql_text = sql_bytes.decode("utf-8")
    except Exception:
        sql_text = ""
    sql_counts = _backup_sql_count_rows(sql_text)

    # ── STAGE 4: compare all three counts ──
    mismatches = []
    for info in per_table:
        t  = info.get("table")
        dbn = int(info.get("db_count") or 0)
        wr  = int(info.get("written")  or 0)
        xls = int(reopen_counts.get(info.get("sheet"), wr))
        sql_c = int(sql_counts.get(t, 0))
        if not (dbn == wr == xls == sql_c):
            mismatches.append({
                "table": t, "db": dbn, "written": wr,
                "excel_reopen": xls, "sql": sql_c,
            })

    if mismatches:
        # ABORT — no file written. The mismatched buffer never touches disk.
        first = mismatches[0]
        msg = ("⚠ فشلت النسخة "
               "الاحتياطية: "
               "عدم تطابق "
               "في عدد صفوف "
               "جدول [" + str(first.get("table") or "") + "] "
               "(في DB: " + str(first.get("db")) + "، "
               "في Excel: " + str(first.get("excel_reopen")) + "، "
               "في SQL: " + str(first.get("sql")) + "). "
               "تم إلغاء الحفظ "
               "لحماية البيانات.")
        try:
            import sys as _sys
            print("[backup] verification mismatch: " + str(mismatches), file=_sys.stderr)
        except Exception: pass
        _publish("error", msg, percent=0, mismatches=mismatches)
        raise RuntimeError(msg)

    # ── Compose verification report ──
    try: u = (session.get("user") or {})
    except Exception: u = {}
    username = u.get("username") or u.get("name") or "system"
    db_kind = "PostgreSQL" if USE_PG else "SQLite"
    fingerprints = {
        xlsx_name + ":": _hashlib.sha256(excel_bytes).hexdigest(),
        sql_name  + ":": _hashlib.sha256(sql_bytes).hexdigest(),
    }
    meta = {
        "zip_name": zip_name, "ts": _dt.datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        "user": username, "kind": kind, "reason": reason or "",
        "db_kind": db_kind,
    }
    report_text = _backup_compose_verification_report(
        meta, per_table, sql_counts, reopen_counts, fingerprints,
    )

    # ── Bundle into zip ──
    _publish("zip", "ضغط الملفات...", percent=85)
    with zipfile.ZipFile(zip_path, "w", zipfile.ZIP_DEFLATED) as zf:
        zf.writestr(xlsx_name, excel_bytes)
        zf.writestr(sql_name,  sql_bytes)
        # UTF-8 BOM so notepad-style readers render Arabic correctly.
        zf.writestr("VERIFICATION_REPORT.txt",
                    "﻿".encode("utf-8") + report_text.encode("utf-8"))
        # Include schema reference + table audit for auditability.
        proj_root = _os.path.dirname(__file__) or "."
        for ref_name in ("CLAUDE.md", "TABLE_AUDIT.md"):
            ref_path = _os.path.join(proj_root, ref_name)
            if _os.path.exists(ref_path):
                try:
                    with open(ref_path, "rb") as f:
                        zf.writestr(ref_name, f.read())
                except Exception:
                    pass

    try: size = _os.path.getsize(zip_path)
    except Exception: size = 0

    recipients_raw = get_setting("backup", "email_recipients", "") or ""
    recipients = [x.strip() for x in recipients_raw.replace(";", ",").split(",") if x.strip()]
    email_status, email_err = _backup_send_email(zip_path, recipients, kind)

    tables_count = len(per_table)
    total_rows   = sum(int(t.get("written") or 0) for t in per_table)
    new_id = None
    try:
        db.execute(
            "INSERT INTO backup_log(username, filename, bytes_written, kind, reason, "
            "path, size_bytes, email_status, email_to, "
            "tables_count, total_rows, verified, report_text) "
            "VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)",
            (username, zip_name, size, kind, reason, zip_path, size,
             email_status, ", ".join(recipients) if recipients else "",
             tables_count, total_rows, 1, report_text),
        )
        db.commit()
        new_id = db.execute("SELECT last_insert_rowid()").fetchone()[0]
    except Exception as ex:
        import sys as _sys
        print("[backup] log insert failed: " + str(ex), file=_sys.stderr)
    # Rotate.
    try:
        keep = int(get_setting("backup", "keep_count", "30") or 30)
    except Exception:
        keep = 30
    try:
        rows = db.execute(
            "SELECT id, path FROM backup_log "
            "WHERE kind IN ('manual', 'scheduled', 'pre-destructive') "
            "ORDER BY id DESC LIMIT 1000"
        ).fetchall()
        old = list(rows)[keep:] if len(list(rows)) > keep else []
        for r in old:
            rid_old = r[0] if not hasattr(r, "keys") else r["id"]
            rpath   = r[1] if not hasattr(r, "keys") else r["path"]
            try:
                if rpath and _os.path.exists(rpath): _os.remove(rpath)
            except Exception: pass
            try: db.execute("DELETE FROM backup_log WHERE id=?", (rid_old,))
            except Exception: pass
        db.commit()
    except Exception: pass

    _publish("done", "تم", percent=100)
    return {
        "id": new_id, "filename": zip_name, "path": zip_path,
        "size_bytes": size, "kind": kind, "reason": reason,
        "email_status": email_status, "email_error": email_err,
        "tables_count": tables_count, "total_rows": total_rows,
        "verified": 1, "report_text": report_text,
        "mismatch": "",
    }


# Module-level progress dict for /api/backup/progress polling. Best-
# effort, last-write-wins; safe enough for one admin clicking once.
_BACKUP_PROGRESS = {"stage": "idle", "msg": "في الانتظار", "percent": 0,
                    "ts": ""}


def _pre_destructive_backup(reason):
    """Hook called before any destructive operation. Runs a backup
    silently. If it fails, raises RuntimeError so the caller can
    BLOCK the destructive op + return the spec error message."""
    db = get_db()
    try:
        info = _create_full_backup(db, kind="pre-destructive", reason=reason or "")
        return info
    except Exception as ex:
        import sys as _sys
        print("[pre-destructive backup] failed: " + str(ex), file=_sys.stderr)
        raise RuntimeError("\u26A0 \u0641\u0634\u0644 \u0627\u0644\u0646\u0633\u062E "
                           "\u0627\u0644\u0627\u062D\u062A\u064A\u0627\u0637\u064A "
                           "\u0627\u0644\u062A\u0644\u0642\u0627\u0626\u064A \u2014 "
                           "\u062A\u0645 \u0625\u0644\u063A\u0627\u0621 "
                           "\u0627\u0644\u0639\u0645\u0644\u064A\u0629 \u0644\u062D\u0645\u0627\u064A\u0629 "
                           "\u0627\u0644\u0628\u064A\u0627\u0646\u0627\u062A")


def _require_admin_response():
    u = session.get("user") or {}
    if (u.get("role") or "").strip().lower() != "admin":
        return jsonify({"ok": False, "error": "admin role required"}), 403
    return None


@app.route('/api/backups/run', methods=['POST'])
@admin_required
def api_backups_run():
    err = _require_admin_response()
    if err: return err
    db = get_db()
    d = request.get_json(silent=True) or {}
    reason = (d.get("reason") or "manual").strip()
    try:
        info = _create_full_backup(db, kind="manual", reason=reason)
        return jsonify({"ok": True, **info})
    except Exception as ex:
        import sys as _sys
        print("[backup] manual run failed: " + str(ex), file=_sys.stderr)
        return jsonify({"ok": False, "error": str(ex)}), 500


# ── Fast table truncation (تفريغ الجدول) ─────────────────────────────
#
# Why this exists: row-by-row DELETE through the per-row API was the
# only way to "empty" a table from قاعدة البيانات. On a real attendance
# table that's thousands of round-trips — slow and prone to timeout.
# This endpoint clears a whole table in ONE database statement after
# an automatic verified backup, so the same operation completes in
# seconds.
#
# Defense-in-depth (every layer below independently blocks abuse):
#   1. /database is @admin_required (managers can't even reach it).
#   2. This endpoint is @admin_required + double-checks via
#      _require_admin_response().
#   3. _TRUNCATE_ALLOWED is a hard whitelist — anything else is 403.
#   4. _TRUNCATE_PROTECTED is an explicit deny-list seen even for
#      tables that might one day be added to the whitelist by mistake.
#   5. table_name is regex-validated [A-Za-z0-9_]+ so it can't contain
#      a SQL fragment, and confirmed against PRAGMA-equivalent schema
#      lookup so a typo can't accidentally hit the wrong table.
#   6. confirm_token must equal the table name (frontend type-to-
#      confirm). No global CSRF system in this app — SameSite=Lax
#      on the session cookie + admin role gate are the actual CSRF
#      defenses; the type-to-confirm enforces user *intent*.
#   7. Auto-backup via _pre_destructive_backup() runs FIRST; if it
#      raises (verification mismatch, disk full, anything), the
#      DELETE is never executed.
#   8. Audit log entry recorded with rows_cleared + backup path.
_TRUNCATE_ALLOWED = {
    "attendance",          # سجل الغياب
    "payment_log",         # سجل الدفع
    "student_payments",    # السجلات الفعلية للدفع
    "payment_edits",       # سجل تعديلات الدفع
    "student_groups",      # معلومات المجموعات
    "evaluations",         # التقييمات الشهرية
    "lessons_log",         # متابعة الدروس
    "parent_messages",     # رسائل المعلمات
    "attendance_late",     # التأخير
    "session_durations",   # مدة الحصص
    "message_log",         # سجل الرسائل
    "point_events",        # أحداث النقاط
    "redemptions",         # المكافآت المستبدلة
    "point_notifications", # إشعارات النقاط
}
_TRUNCATE_PROTECTED = {
    "users", "students", "taqseet", "parent_receipts",
    "audit_log", "backup_log",
    "curriculum_files", "curriculum_assignments", "curriculum_access_log",
    "docs_pages", "docs_screenshots",
    "settings", "schema_migrations", "table_labels",
}


def _truncate_table_exists(db, table_name):
    """Return True iff `table_name` exists in the live DB schema.
    Uses sqlite_master locally, information_schema on Postgres."""
    try:
        if USE_PG:
            row = db.execute(
                "SELECT 1 FROM information_schema.tables "
                "WHERE table_schema='public' AND table_name=? LIMIT 1",
                (table_name,)
            ).fetchone()
        else:
            row = db.execute(
                "SELECT 1 FROM sqlite_master "
                "WHERE type='table' AND name=? LIMIT 1",
                (table_name,)
            ).fetchone()
        return bool(row)
    except Exception:
        return False


@app.route('/api/admin/table/truncate', methods=['POST'])
@admin_required
def api_admin_table_truncate():
    err = _require_admin_response()
    if err: return err
    db = get_db()
    d = request.get_json(silent=True) or {}
    table_name    = (d.get("table_name") or "").strip()
    confirm_token = (d.get("confirm_token") or "").strip()

    # ── Validation gauntlet ──
    if not table_name:
        return jsonify({"ok": False,
                        "error": "&#x627;&#x633;&#x645; &#x627;&#x644;&#x62C;&#x62F;&#x648;&#x644; &#x645;&#x637;&#x644;&#x648;&#x628;"}), 400
    # Strict identifier — no quotes, no spaces, no SQL fragments.
    if not _re.match(r"^[A-Za-z0-9_]+$", table_name):
        return jsonify({"ok": False,
                        "error": "&#x627;&#x633;&#x645; &#x627;&#x644;&#x62C;&#x62F;&#x648;&#x644; &#x63A;&#x64A;&#x631; &#x635;&#x627;&#x644;&#x62D;"}), 400
    # Type-to-confirm check (frontend made the user type the name).
    if confirm_token != table_name:
        return jsonify({"ok": False,
                        "error": "&#x627;&#x644;&#x62A;&#x623;&#x643;&#x64A;&#x62F; &#x63A;&#x64A;&#x631; &#x645;&#x637;&#x627;&#x628;&#x642;"}), 400
    # Protected (deny-list).
    tn_lower = table_name.lower()
    if (tn_lower in _TRUNCATE_PROTECTED
        or tn_lower.startswith("backup_")
        or tn_lower.startswith("system_")):
        return jsonify({"ok": False,
                        "error": "&#x647;&#x630;&#x627; &#x627;&#x644;&#x62C;&#x62F;&#x648;&#x644; &#x645;&#x62D;&#x645;&#x64A;"}), 403
    # Whitelist (allow-list).
    if tn_lower not in _TRUNCATE_ALLOWED:
        return jsonify({"ok": False,
                        "error": "&#x647;&#x630;&#x627; &#x627;&#x644;&#x62C;&#x62F;&#x648;&#x644; &#x63A;&#x64A;&#x631; &#x645;&#x633;&#x645;&#x648;&#x62D; &#x628;&#x62A;&#x641;&#x631;&#x64A;&#x63A;&#x647;"}), 403
    # Schema existence (the table must really live in this DB).
    if not _truncate_table_exists(db, table_name):
        return jsonify({"ok": False,
                        "error": "&#x627;&#x644;&#x62C;&#x62F;&#x648;&#x644; &#x63A;&#x64A;&#x631; &#x645;&#x648;&#x62C;&#x648;&#x62F;"}), 404

    # ── Pre-truncate row count ──
    try:
        pre_count = int(db.execute(
            'SELECT COUNT(*) FROM "' + table_name + '"'
        ).fetchone()[0] or 0)
    except Exception as ex:
        return jsonify({"ok": False,
                        "error": "&#x62A;&#x639;&#x630;&#x631; &#x639;&#x62F; &#x627;&#x644;&#x635;&#x641;&#x648;&#x641;: " + str(ex)}), 500

    # ── Mandatory verified backup ──
    try:
        bk_info = _pre_destructive_backup(
            "truncate:" + table_name + " (rows=" + str(pre_count) + ")"
        )
    except Exception as ex:
        import sys as _sys
        print("[truncate] backup failed: " + str(ex), file=_sys.stderr)
        return jsonify({
            "ok": False,
            "error": "&#x62A;&#x639;&#x630;&#x631; &#x625;&#x646;&#x634;&#x627;&#x621; &#x646;&#x633;&#x62E;&#x629; &#x627;&#x62D;&#x62A;&#x64A;&#x627;&#x637;&#x64A;&#x629;. &#x644;&#x627; &#x64A;&#x645;&#x643;&#x646; &#x627;&#x644;&#x645;&#x62A;&#x627;&#x628;&#x639;&#x629; &#x628;&#x62F;&#x648;&#x646; &#x646;&#x633;&#x62E;&#x629; &#x645;&#x62D;&#x641;&#x648;&#x638;&#x629;.",
        }), 500

    # ── Atomic single-statement truncate ──
    # A single DELETE is a transaction in both SQLite and Postgres.
    # We use DELETE (not TRUNCATE) so triggers / FK ON DELETE rules
    # fire normally and rollback semantics stay consistent with the
    # rest of the app's row-level deletes.
    rows_cleared = 0
    try:
        cur = db.execute('DELETE FROM "' + table_name + '"')
        try:
            rows_cleared = int(cur.rowcount or 0)
        except Exception:
            rows_cleared = pre_count
        db.commit()
    except Exception as ex:
        try: db.rollback()
        except Exception: pass
        import sys as _sys
        print("[truncate] DELETE failed: " + str(ex), file=_sys.stderr)
        return jsonify({"ok": False,
                        "error": "&#x641;&#x634;&#x644; &#x627;&#x644;&#x62A;&#x641;&#x631;&#x64A;&#x63A;: " + str(ex)}), 500

    # Reset autoincrement so the next inserted row starts at 1 again.
    # SQLite-only — Postgres sequence reset is skipped (sequence name
    # varies and a non-reset sequence is harmless).
    if not USE_PG:
        try:
            db.execute("DELETE FROM sqlite_sequence WHERE name=?", (table_name,))
            db.commit()
        except Exception:
            pass

    # ── Post-truncate verification ──
    try:
        post_count = int(db.execute(
            'SELECT COUNT(*) FROM "' + table_name + '"'
        ).fetchone()[0] or 0)
    except Exception:
        post_count = -1

    # ── Audit log ──
    try:
        u = session.get("user") or {}
        _audit(
            "table.truncate",
            target_type="table", target_id=table_name,
            old_value={"rows": pre_count},
            new_value={"rows": post_count},
            details={
                "rows_cleared": rows_cleared,
                "backup_filename": bk_info.get("filename"),
                "backup_path": bk_info.get("path"),
                "actor": u.get("username") or "",
            },
        )
    except Exception:
        pass

    return jsonify({
        "ok": True,
        "success": True,
        "table": table_name,
        "rows_cleared": rows_cleared,
        "pre_count": pre_count,
        "post_count": post_count,
        "backup_path": bk_info.get("path") or "",
        "backup_filename": bk_info.get("filename") or "",
        "backup_id": bk_info.get("id"),
    })


@app.route('/api/backups', methods=['GET'])
@admin_required
def api_backups_list():
    err = _require_admin_response()
    if err: return err
    db = get_db()
    try:
        rows = db.execute(
            "SELECT id, username, filename, bytes_written, downloaded_at AS created_at, "
            "       COALESCE(kind, \'manual\') AS kind, "
            "       COALESCE(reason, \'\') AS reason, "
            "       COALESCE(path, \'\') AS path, "
            "       COALESCE(size_bytes, 0) AS size_bytes, "
            "       COALESCE(email_status, \'\') AS email_status, "
            "       COALESCE(email_to, \'\') AS email_to, "
            "       COALESCE(tables_count, 0) AS tables_count, "
            "       COALESCE(total_rows, 0) AS total_rows, "
            "       COALESCE(verified, 0) AS verified "
            "FROM backup_log ORDER BY id DESC LIMIT 500"
        ).fetchall()
    except Exception as ex:
        return jsonify({"ok": False, "error": str(ex)}), 500
    out = [dict(r) for r in rows]
    return jsonify({"ok": True, "rows": out})


@app.route('/api/backups/<int:bid>/report', methods=['GET'])
@admin_required
def api_backups_report(bid):
    """Return the saved verification report for a backup_log row."""
    err = _require_admin_response()
    if err: return err
    db = get_db()
    try:
        row = db.execute(
            "SELECT id, filename, COALESCE(report_text,'') AS report_text, "
            "       COALESCE(tables_count,0) AS tables_count, "
            "       COALESCE(total_rows,0) AS total_rows, "
            "       COALESCE(verified,0) AS verified "
            "FROM backup_log WHERE id=?", (bid,),
        ).fetchone()
    except Exception as ex:
        return jsonify({"ok": False, "error": str(ex)}), 500
    if not row:
        return jsonify({"ok": False, "error": "not found"}), 404
    return jsonify({"ok": True, **dict(row)})


