# ── Grant points ─────────────────────────────────────────────────
@app.route('/api/points/grant', methods=['POST'])
@login_required
def api_pts_grant():
    """Body: { student_ids: [int], behavior_id: int, group_name: str,
    note?: str, points_override?: int }. Permission: admin/manager
    always; teacher only if group_name is one of their groups. Returns
    grant count and new balances per student.

    `points_override` (signed integer) lets the bulk-adjust page
    (/points/bulk-adjust) re-use this exact endpoint with the special
    "تعديل يدوي" behavior — the behavior's own points_value is 0, the
    actual delta comes per-call. Clamped to [-1000, 1000] so a typo
    can't blow up balances. All other side-effects (point_events row,
    parent notifications, balance recomputation) are unchanged.
    """
    user = session.get("user") or {}
    d = request.get_json(silent=True) or {}
    sids = d.get("student_ids") or []
    if isinstance(sids, (int, str)):
        sids = [sids]
    try:
        sids = [int(x) for x in sids if str(x).strip()]
    except Exception:
        return jsonify({"ok": False, "error": "invalid student_ids"}), 400
    if not sids:
        return jsonify({"ok": False, "error": "at least one student_id required"}), 400
    try:
        bid = int(d.get("behavior_id") or 0)
    except Exception:
        bid = 0
    if not bid:
        return jsonify({"ok": False, "error": "behavior_id required"}), 400
    group_name = (d.get("group_name") or "").strip()
    note       = (d.get("note") or "").strip()
    # Optional custom delta (bulk-adjust). Falls back to None when
    # absent so the legacy single-behavior flow uses behaviors.points_value.
    points_override = None
    if "points_override" in d and d.get("points_override") not in (None, "", 0):
        try:
            points_override = int(d.get("points_override"))
        except Exception:
            return jsonify({"ok": False, "error": "invalid points_override"}), 400
        # Sanity clamp — bigger deltas are almost always typos.
        if points_override < -1000 or points_override > 1000:
            return jsonify({"ok": False, "error": "points_override out of range"}), 400
    db = get_db()
    if not _pts_can_grant(db, user, group_name):
        return jsonify({"ok": False, "error": "forbidden for this group"}), 403
    try:
        b = db.execute(
            "SELECT id, name_ar, type, points_value, icon, color, is_active "
            "FROM behaviors WHERE id=?", (bid,),
        ).fetchone()
    except Exception:
        b = None
    if not b:
        return jsonify({"ok": False, "error": "behavior not found"}), 404
    bd = dict(b)
    if not bd.get("is_active"):
        return jsonify({"ok": False, "error": "behavior inactive"}), 400
    pv = int(bd.get("points_value") or 0)
    if points_override is not None:
        pv = points_override
    awarded_by = user.get("id") or 0
    awarded_by_name = (user.get("name") or user.get("username") or "").strip()
    notify_on = (get_setting("points", "auto_notify_parent", "0") or "0") == "1"
    results = []
    for sid in sids:
        try:
            srow = db.execute("SELECT student_name FROM students WHERE id=?", (sid,)).fetchone()
        except Exception:
            srow = None
        sname = (dict(srow).get("student_name") if srow else "") or ""
        try:
            cur = db.execute(
                "INSERT INTO point_events(student_id, student_name, behavior_id, "
                "behavior_name, points_value, group_name, awarded_by, "
                "awarded_by_name, note) VALUES(?,?,?,?,?,?,?,?,?)",
                (sid, sname, bid, bd.get("name_ar") or "",
                 pv, group_name, awarded_by, awarded_by_name, note),
            )
            db.commit()
            event_id = cur.lastrowid
        except Exception as ex:
            results.append({"student_id": sid, "ok": False, "error": str(ex)})
            continue
        bal = _pts_balance(db, sid)
        # Queue parent WhatsApp notification — skipped if the linked
        # parent has notify_pref in {daily, weekly, off}, since those
        # are handled by the digest scheduler instead.
        if notify_on:
            parent_pref = _pts_parent_pref_for_student(db, sid)
            if parent_pref in ("daily", "weekly", "off"):
                pass  # digest scheduler will handle (or skip if off)
            else:
                phone = _pts_get_student_phone(db, sid)
                msg = _pts_format_event_message(sname, bd.get("name_ar") or "",
                                                pv, awarded_by_name, bal)
                try:
                    db.execute(
                        "INSERT INTO point_notifications(event_id, student_id, "
                        "student_name, phone, message, status, notification_type) "
                        "VALUES(?,?,?,?,?,?,?)",
                        (event_id, sid, sname, phone, msg, "pending", "instant"),
                    )
                    db.commit()
                except Exception:
                    pass
        results.append({
            "student_id": sid, "ok": True,
            "event_id": event_id, "balance": bal,
            "student_name": sname,
        })
    return jsonify({
        "ok": True,
        "behavior":   bd,
        "granted_to": sum(1 for r in results if r.get("ok")),
        "results":    results,
    })


