# Arabic day names — used by the days-extractor below to detect
# which row column actually carries the schedule's days.
_AR_DAY_NAMES = (
    "\u0627\u0644\u0633\u0628\u062A",       # السبت  Saturday
    "\u0627\u0644\u0623\u062D\u062F",        # الأحد  Sunday
    "\u0627\u0644\u0625\u062B\u0646\u064A\u0646",  # الإثنين Monday
    "\u0627\u0644\u062B\u0644\u0627\u062B\u0627\u0621",  # الثلاثاء Tuesday
    "\u0627\u0644\u0623\u0631\u0628\u0639\u0627\u0621",  # الأربعاء Wednesday
    "\u0627\u0644\u062E\u0645\u064A\u0633",       # الخميس Thursday
    "\u0627\u0644\u062C\u0645\u0639\u0629",       # الجمعة Friday
    # Bare-name variants (no leading "ال")
    "\u0633\u0628\u062A", "\u0623\u062D\u062F", "\u0625\u062B\u0646\u064A\u0646",
    "\u062B\u0644\u0627\u062B\u0627\u0621", "\u0623\u0631\u0628\u0639\u0627\u0621",
    "\u062E\u0645\u064A\u0633", "\u062C\u0645\u0639\u0629",
)


def _value_has_arabic_day(s):
    if not s: return False
    s = str(s)
    for d in _AR_DAY_NAMES:
        if d in s: return True
    return False


def _normalize_days_string(s):
    """Accept comma-separated (ASCII , or Arabic ،), JSON arrays, or
    free-form text containing day names. Return a clean
    "الأحد، الثلاثاء، الخميس"-style string."""
    s = (s or "").strip()
    if not s: return ""
    # JSON array?
    if s.startswith("[") and s.endswith("]"):
        try:
            import json as _json
            arr = _json.loads(s)
            if isinstance(arr, list):
                parts = [str(x).strip() for x in arr if str(x).strip()]
                return "\u060C ".join(parts)
        except Exception:
            pass
    # Has comma separator → split + rejoin with Arabic comma.
    if ("," in s) or ("\u060C" in s):
        parts = [p.strip() for p in s.replace(",", "\u060C").split("\u060C") if p.strip()]
        return "\u060C ".join(parts)
    # Single token / free-form — leave as-is.
    return s


_DAY_TIME_COLS = ("study_time", "ramadan_time", "online_time")
_COL_NAME_DAY_HINTS_LOWER = ("days", "day_list", "day-list", "days_of_week",
                              "weekdays", "day_of_week", "schedule_days")
_COL_NAME_DAY_HINTS_AR = ("\u0623\u064A\u0627\u0645", "\u0627\u064A\u0627\u0645",
                           "\u064A\u0648\u0645")

# Authoritative-days resolution. The admin's "تعديل الجدول" modal can
# add a new column to student_groups and label it "\u0623\u064A\u0627\u0645 \u0627\u0644\u062F\u0631\u0627\u0633\u0629" — the
# label is stored in group_col_labels with an auto-generated col_key
# like col_<timestamp>. When that happens the user starts typing days
# into the new column; the legacy `study_days` column may sit stale.
# _groups_days_column resolves which column on student_groups should
# be treated as the authoritative source for that request, falling
# back to the canonical study_days when no custom column is labelled.
_GROUPS_DAYS_LABEL_TARGET = "\u0623\u064A\u0627\u0645 \u0627\u0644\u062F\u0631\u0627\u0633\u0629"

def _groups_days_column(db):
    """Internal column on student_groups that holds the authoritative
    'أيام الدراسة' values. Looks up group_col_labels and matches on
    the FOLDED + ENTITY-DECODED form of the label so a user-added
    column that the edit-table modal stored with HTML entities
    (&#x623;&#x64A;&#x627;&#x645; &#x627;&#x644;&#x62F;&#x631;&#x627;&#x633;&#x629; → 'أيام الدراسة')
    is recognised. Cached on flask.g per request. Always returns a
    non-empty string — defaults to 'study_days' when no custom-
    labelled column is found."""
    try:
        from flask import g as _g
    except Exception:
        _g = None
    if _g is not None and hasattr(_g, "_groups_days_col"):
        return _g._groups_days_col
    resolved = "study_days"
    try:
        live = {r[1] for r in db.execute("PRAGMA table_info(student_groups)").fetchall()}
    except Exception:
        live = set()
    try:
        rows = db.execute(
            "SELECT col_key, col_label FROM group_col_labels"
        ).fetchall()
    except Exception:
        rows = []
    target_norm = _grp_norm(_GROUPS_DAYS_LABEL_TARGET)
    for r in rows:
        rd = dict(r) if hasattr(r, "keys") else None
        ck = (rd["col_key"] if rd else r[0]) or ""
        cl = (rd["col_label"] if rd else (r[1] if len(r) > 1 else "")) or ""
        ck = ck.strip()
        if not ck or ck == "study_days":
            continue
        if not _is_safe_ident(ck):
            continue
        if ck not in live:
            continue
        # Compare in folded form, after first decoding HTML numeric
        # entities (the edit-table modal stores Arabic labels in
        # entity form, e.g. '&#x623;&#x64A;&#x627;&#x645; ...') so the
        # raw cell never matches a literal-string compare. _grp_norm
        # also folds alif / hamza / teh-marbuta variants so a label
        # typed 'ايام الدراسه' resolves to the same target.
        decoded = _decode_arabic_entities(cl).strip()
        if _grp_norm(decoded) == target_norm:
            resolved = ck
            break
    if _g is not None:
        try: _g._groups_days_col = resolved
        except Exception: pass
    return resolved

def _row_days_authoritative(rd, days_col=None):
    """Per-row resolver for the authoritative days value. Prefers
    `days_col` (the user-added 'أيام الدراسة' column when distinct),
    falling back to study_days when the preferred column is empty
    for THIS row — handles partially-migrated tables gracefully."""
    if days_col and days_col != "study_days":
        v = rd.get(days_col)
        if isinstance(v, str): v = v.strip()
        if v: return v
    v = rd.get("study_days") or ""
    return v.strip() if isinstance(v, str) else (str(v) if v else "")
_BOOL_DAY_COLS = (
    ("day_sat", "\u0627\u0644\u0633\u0628\u062A"),
    ("day_sun", "\u0627\u0644\u0623\u062D\u062F"),
    ("day_mon", "\u0627\u0644\u0625\u062B\u0646\u064A\u0646"),
    ("day_tue", "\u0627\u0644\u062B\u0644\u0627\u062B\u0627\u0621"),
    ("day_wed", "\u0627\u0644\u0623\u0631\u0628\u0639\u0627\u0621"),
    ("day_thu", "\u0627\u0644\u062E\u0645\u064A\u0633"),
    ("day_fri", "\u0627\u0644\u062C\u0645\u0639\u0629"),
)
_EN_TO_AR_DAY = {
    "saturday":  "\u0627\u0644\u0633\u0628\u062A",
    "sunday":    "\u0627\u0644\u0623\u062D\u062F",
    "monday":    "\u0627\u0644\u0625\u062B\u0646\u064A\u0646",
    "tuesday":   "\u0627\u0644\u062B\u0644\u0627\u062B\u0627\u0621",
    "wednesday": "\u0627\u0644\u0623\u0631\u0628\u0639\u0627\u0621",
    "thursday":  "\u0627\u0644\u062E\u0645\u064A\u0633",
    "friday":    "\u0627\u0644\u062C\u0645\u0639\u0629",
}

def _translate_english_days(s):
    """Replace English weekday names (case-insensitive) with their
    Arabic equivalents in `s`."""
    if not s: return s
    import re as _re
    def _sub(m):
        return _EN_TO_AR_DAY.get(m.group(0).lower(), m.group(0))
    return _re.sub(r"(?i)\b(saturday|sunday|monday|tuesday|wednesday|thursday|friday)\b", _sub, s)


def _is_truthy_flag(v):
    if v is None: return False
    if isinstance(v, bool): return v
    if isinstance(v, (int, float)): return v != 0
    s = str(v).strip().lower()
    return s in ("1", "true", "yes", "y", "\u0646\u0639\u0645", "\u0635\u062D")


def _extract_days_from_row(rd):
    """Multi-strategy extractor. Returns a normalised Arabic-comma
    days string or empty. Optional MX_DEBUG_GROUPS env flag prints
    the strategy picked + raw value for each row to stderr."""
    import os as _os, sys as _sys
    debug = bool(_os.environ.get("MX_DEBUG_GROUPS"))
    name = (rd.get("group_name") or "").strip()
    # Strategy 0: authoritative column resolved from group_col_labels.
    # Whichever column the admin labelled "أيام الدراسة" (the canonical
    # study_days OR a user-added col_<timestamp>) wins, provided the
    # row dict was fetched with that column included. Resolved per-
    # request via flask.g; lazily primed here for handlers that didn't
    # call _groups_days_column themselves.
    _auth_col = None
    try:
        from flask import g as _g, has_request_context
        if has_request_context():
            _auth_col = getattr(_g, '_groups_days_col', None)
            if _auth_col is None:
                try:
                    _auth_col = _groups_days_column(get_db())
                except Exception:
                    _auth_col = None
    except Exception:
        _auth_col = None
    if _auth_col and _auth_col != 'study_days' and _auth_col in rd:
        av = rd.get(_auth_col)
        if isinstance(av, str): av = av.strip()
        if av:
            if debug: print("[mx-days] " + name + ": strategy=label-resolved col=" + repr(_auth_col) + " raw=" + repr(av), file=_sys.stderr)
            return _translate_english_days(_normalize_days_string(av))
    # Strategy 1: canonical study_days.
    v = (rd.get("study_days") or "")
    if isinstance(v, str): v = v.strip()
    if v:
        if debug: print("[mx-days] " + name + ": strategy=study_days raw=" + repr(v), file=_sys.stderr)
        return _translate_english_days(_normalize_days_string(v))
    # Strategy 2: any column whose NAME hints at days, regardless of
    # the value's language/format.
    for col, val in rd.items():
        if col in _DAY_TIME_COLS or col in ("group_name", "teacher_name", "study_days"):
            continue
        if val is None: continue
        sv = str(val).strip()
        if not sv: continue
        col_lc = col.lower()
        hint_en = any(h in col_lc for h in _COL_NAME_DAY_HINTS_LOWER)
        hint_ar = any(h in col for h in _COL_NAME_DAY_HINTS_AR)
        if hint_en or hint_ar:
            if debug: print("[mx-days] " + name + ": strategy=col-name-hint col=" + repr(col) + " raw=" + repr(sv), file=_sys.stderr)
            return _translate_english_days(_normalize_days_string(sv))
    # Strategy 3: value contains an Arabic day name.
    for col, val in rd.items():
        if col in _DAY_TIME_COLS or col in ("group_name", "teacher_name", "study_days"):
            continue
        if val is None: continue
        sv = str(val).strip()
        if not sv: continue
        if _value_has_arabic_day(sv):
            if debug: print("[mx-days] " + name + ": strategy=value-arabic-day col=" + repr(col) + " raw=" + repr(sv), file=_sys.stderr)
            return _normalize_days_string(sv)
    # Strategy 4: boolean per-day columns.
    found = []
    for cname, label in _BOOL_DAY_COLS:
        if cname in rd and _is_truthy_flag(rd.get(cname)):
            found.append(label)
    if found:
        joined = "\u060C ".join(found)
        if debug: print("[mx-days] " + name + ": strategy=bool-cols joined=" + repr(joined), file=_sys.stderr)
        return joined
    if debug: print("[mx-days] " + name + ": strategy=none (empty)", file=_sys.stderr)
    return ""


def _teacher_groups_detailed_for(db, user):
    """Same teacher → groups mapping as `_teacher_groups_for`, but
    each entry carries every schedule column the teacher dropdown
    might surface AND a normalised study_days string resolved via
    _extract_days_from_row (which tries 4 strategies in priority
    order — see helper above). Set MX_DEBUG_GROUPS=1 in the env
    to print each row's extracted strategy to stderr."""
    keys = _teacher_match_keys(user)
    if not keys:
        return []
    try:
        live_cols = [r[1] for r in db.execute("PRAGMA table_info(student_groups)").fetchall()]
    except Exception:
        live_cols = []
    if not live_cols:
        return []
    try:
        rows = db.execute(
            'SELECT * FROM student_groups '
            "WHERE group_name IS NOT NULL AND TRIM(group_name) <> ''"
        ).fetchall()
    except Exception:
        return []
    out, seen = [], set()
    for r in rows:
        rd = dict(r) if hasattr(r, "keys") else {live_cols[i]: r[i] for i in range(len(live_cols)) if i < len(r)}
        gn = (rd.get("group_name") or "").strip()
        tn = (rd.get("teacher_name") or "").strip().lower()
        if not gn or not tn or tn not in keys: continue
        if gn in seen: continue
        seen.add(gn)
        out.append({
            "name":          gn,
            "study_days":    _extract_days_from_row(rd),
            "study_time":   (rd.get("study_time")   or "").strip(),
            "ramadan_time": (rd.get("ramadan_time") or "").strip(),
            "online_time":  (rd.get("online_time")  or "").strip(),
        })
    out.sort(key=lambda g: g["name"])
    return out


def _teacher_mode_filtered_groups(db, user, mode):
    """The teacher's owned groups, filtered by which student column
    references each group AND respecting group-level mode_exceptions.

    Default rule:
      - mode = أونلاين → keep only groups referenced via
        students.group_online
      - mode = حضوري | رمضان → keep only groups referenced via
        students.group_name_student

    Exception override (per-group): if mode_exceptions has a row
    {scope=group, key_name=<group>, mode=<E>}, the group is shown
    ONLY when global mode == E (its column-of-reference is ignored
    for the visibility decision). Per spec point 7.

    Returns the same shape as _teacher_groups_detailed_for: list of
    {name, study_days, study_time}."""
    if mode not in VALID_CENTER_MODES:
        mode = _center_mode_default()
    owned = _teacher_groups_detailed_for(db, user)
    if not owned:
        return []
    owned_index = {g["name"]: g for g in owned}

    # Tag every group referenced in students table with the kinds it
    # appears under. kinds: 'online' (group_online column) or
    # 'in-person' (group_name_student column).
    kinds = {}
    try:
        rows = db.execute(
            "SELECT group_name_student, group_online FROM students"
        ).fetchall()
    except Exception:
        rows = []
    for r in rows:
        rd = dict(r) if hasattr(r, "keys") else {
            "group_name_student": r[0] if len(r) > 0 else "",
            "group_online":       r[1] if len(r) > 1 else "",
        }
        gn1 = (rd.get("group_name_student") or "").strip()
        gn2 = (rd.get("group_online")       or "").strip()
        if gn1: kinds.setdefault(gn1, set()).add("in-person")
        if gn2: kinds.setdefault(gn2, set()).add("online")

    # Group-level exceptions.
    try:
        exc_rows = db.execute(
            "SELECT key_name, mode FROM mode_exceptions WHERE scope=\'group\'"
        ).fetchall()
    except Exception:
        exc_rows = []
    exc_map = {}
    for r in exc_rows:
        rd = dict(r) if hasattr(r, "keys") else {"key_name": r[0], "mode": r[1]}
        kn = (rd.get("key_name") or "").strip()
        md = (rd.get("mode")     or "").strip()
        if kn and md: exc_map[kn] = md

    is_online = (mode == "\u0623\u0648\u0646\u0644\u0627\u064A\u0646")
    is_ramadan = (mode == "\u0631\u0645\u0636\u0627\u0646")
    def _decorate(g, used_mode):
        """Pick the right time column for this mode and put it on a
        flat `schedule` field. Days come from the normalised
        study_days; if the time column ALREADY embeds the days, we
        skip the prepend so we don't duplicate."""
        gd = dict(g)
        if used_mode == "\u0623\u0648\u0646\u0644\u0627\u064A\u0646":
            sched_time = gd.get("online_time") or gd.get("study_time") or ""
        elif used_mode == "\u0631\u0645\u0636\u0627\u0646":
            sched_time = gd.get("ramadan_time") or gd.get("study_time") or ""
        else:
            sched_time = gd.get("study_time") or ""
        days = (gd.get("study_days") or "").strip()
        time_has_days = _value_has_arabic_day(sched_time)
        if days and sched_time and not time_has_days:
            sched = days + " - " + sched_time
        elif days and not sched_time:
            sched = days
        else:
            sched = sched_time
        gd["schedule"] = (sched or "").strip()
        gd["used_mode"] = used_mode
        return gd
    out = []
    for gn, g in owned_index.items():
        ex = exc_map.get(gn)
        if ex:
            if ex == mode:
                out.append(_decorate(g, ex))
            continue
        kset = kinds.get(gn, set())
        if is_online:
            if "online" in kset:
                out.append(_decorate(g, mode))
        else:
            if "in-person" in kset:
                out.append(_decorate(g, mode))
    out.sort(key=lambda g: g["name"])
    return out


def _require_teacher():
    """Returns (user_dict, error_response_or_None). Used at the top
    of every /api/teacher/* route to gate access."""
    user = session.get("user") or {}
    role = (user.get("role") or "").strip().lower()
    if role != "teacher":
        return user, (jsonify({"ok": False, "error": "forbidden"}), 403)
    return user, None


