    role = (user.get("role") or "").strip().lower()
    if role != "teacher":
        return redirect("/dashboard")
    who = (user.get("name") or user.get("username") or "").strip()
    return TEACHER_ATTENDANCE_HTML.replace("USER_PLACEHOLDER", who)


