@app.route('/api/teacher/students', methods=['GET'])
@login_required
def api_teacher_students():
    # Teacher attendance loader. Restricts the result to actively-
    # registered students per settings.students.active_column /
    # active_value (defaults: registration_term2_2026 = "تم التسجيل").
    # Defensive: don't rely on _active_students_filter() returning a
    # usable fragment — if /settings is cleared we still want this gate
    # ON, so we resolve the column + value here directly with hardcoded
    # fallbacks. The filter applies only to the teacher attendance
    # surface; بحث عن طالب and the admin قاعدة بيانات الطلبة view keep
    # showing every student regardless of registration.
    user, err = _require_teacher()
    if err: return err
    group = (request.args.get('group') or '').strip()
    if not group:
        return jsonify({"ok": False, "error": "group is required"}), 400
    db = get_db()
    own = _teacher_groups_for(db, user)
    if group not in own:
        return jsonify({"ok": False, "error": "forbidden"}), 403
    in_col     = get_setting('attendance', 'student_group_column',         'group_name_student')
    online_col = get_setting('attendance', 'student_online_group_column',  'group_online')
    if not _is_safe_ident(in_col):     in_col = 'group_name_student'
    if not _is_safe_ident(online_col): online_col = 'group_online'
    try:
        live = {r[1] for r in db.execute("PRAGMA table_info(students)").fetchall()}
    except Exception:
        live = set()
    has_online = (online_col in live and online_col != in_col)
    where = '"' + in_col + '" = ?'
    params = (group,)
    if has_online:
        where = '"' + in_col + '" = ? OR "' + online_col + '" = ?'
        params = (group, group)
    act_col = (get_setting('students', 'active_column', 'registration_term2_2026') or '').strip() \
              or 'registration_term2_2026'
    act_val = (get_setting('students', 'active_value',  'تم التسجيل') or '').strip() \
              or 'تم التسجيل'
    if not _is_safe_ident(act_col):
        act_col = 'registration_term2_2026'
    if act_col in live:
        where = '(' + where + ') AND TRIM(COALESCE("' + act_col + '", \'\')) = ?'
        params = tuple(list(params) + [act_val])
    try:
        rows = db.execute(
            'SELECT id, student_name, whatsapp FROM students WHERE ' + where +
            ' ORDER BY student_name', params
        ).fetchall()
    except Exception as ex:
        return jsonify({"ok": False, "error": str(ex)}), 500
    out = []
    for r in rows:
        nm = (r[1] or '').strip()
        if not nm: continue
        out.append({"id": r[0], "name": nm, "whatsapp": r[2] or ''})
    return jsonify({"ok": True, "students": out, "group": group})


@app.route('/api/teacher/attendance/check', methods=['GET'])
@login_required
def api_teacher_attendance_check():
    user, err = _require_teacher()
    if err: return err
    group = (request.args.get('group') or '').strip()
    date  = (request.args.get('date')  or '').strip()
    if not group or not date:
        return jsonify({"ok": True, "exists": False, "records": []})
    db = get_db()
    if group not in _teacher_groups_for(db, user):
        return jsonify({"ok": False, "error": "forbidden"}), 403
    target = _att_normalize_date(date)
    rows = db.execute(
        "SELECT * FROM attendance WHERE TRIM(group_name)=TRIM(?)",
        (group,)
    ).fetchall()
    out = []
    for r in rows:
        if _att_normalize_date(r["attendance_date"]) == target:
            out.append(dict(r))
    return jsonify({"ok": True, "exists": len(out) > 0, "records": out})


@app.route('/api/teacher/attendance', methods=['POST'])
@login_required
def api_teacher_attendance_save():
    """Bulk save: upserts each row in `rows` keyed by
    (attendance_date, group_name, student_name). Mirrors the رصد
    الغياب POST behaviour. Permission-gated to the teacher's own
    groups."""
    user, err = _require_teacher()
    if err: return err
    d = request.get_json() or {}
    group = (d.get('group_name') or '').strip()
    date_raw = (d.get('attendance_date') or '').strip()
    day_name = (d.get('day_name') or '').strip()
    rows = d.get('rows') or []
    if not group or not date_raw:
        return jsonify({"ok": False, "error": "group_name and attendance_date are required"}), 400
    if not isinstance(rows, list):
        return jsonify({"ok": False, "error": "rows must be a list"}), 400
    db = get_db()
    if group not in _teacher_groups_for(db, user):
        return jsonify({"ok": False, "error": "forbidden"}), 403
    iso_date = _att_normalize_date(date_raw) or date_raw
    inserted = 0; updated = 0; skipped = 0
    for raw in rows:
        if not isinstance(raw, dict):
            skipped += 1; continue
        sname = (raw.get('student_name') or '').strip()
        sname = " ".join(sname.split())
        if not sname:
            skipped += 1; continue
        status = (raw.get('status') or '').strip()
        if status:
            status = STATUS_REMAP.get(status, status)
        contact = (raw.get('contact_number') or '').strip()
        body = {
            "attendance_date": iso_date,
            "day_name":        day_name,
            "group_name":      group,
            "student_name":    sname,
            "contact_number":  contact,
            "status":          status,
        }
        # Honor per-row override if the client sent one; otherwise
        # auto-resolve via the active center mode + the student's
        # group references.
        try:
            sid_lookup = db.execute(
                "SELECT id FROM students WHERE TRIM(student_name)=TRIM(?) LIMIT 1",
                (sname,),
            ).fetchone()
        except Exception:
            sid_lookup = None
        _sid = sid_lookup[0] if sid_lookup else None
        _override_dur = (raw.get("class_duration") or "").strip() if isinstance(raw, dict) else ""
        _override_typ = (raw.get("class_type")     or "").strip() if isinstance(raw, dict) else ""
        if _override_dur or _override_typ:
            if _override_dur: body["class_duration"] = _override_dur
            if _override_typ: body["class_type"]     = _override_typ
        elif _sid:
            try:
                meta = _resolve_center_class_meta(db, _get_center_mode(db), _sid)
                body["class_duration"] = meta.get("class_duration") or ""
                body["class_type"]     = meta.get("class_type")     or ""
            except Exception:
                pass
        try:
            existing = db.execute(
                "SELECT id FROM attendance WHERE student_name=? AND attendance_date=? AND group_name=?",
                (sname, iso_date, group),
            ).fetchone()
        except Exception:
            existing = None
        try:
            if existing:
                rid = existing[0] if not hasattr(existing, "keys") else existing["id"]
                _attendance_dynamic_update(db, rid, body)
                updated += 1
            else:
                _attendance_dynamic_insert(db, body)
                inserted += 1
        except Exception as ex:
            import sys as _sys
            print("[teacher attendance] write failed: " + str(ex), file=_sys.stderr)
            try: db.rollback()
            except Exception: pass
            skipped += 1
    db.commit()
    return jsonify({
        "ok": True,
        "inserted": inserted,
        "updated":  updated,
        "skipped":  skipped,
    })


@app.route('/api/attendance', methods=['GET'])
@login_required
def api_attendance_get():
    db = get_db()
    rows = db.execute("SELECT * FROM attendance ORDER BY id ASC").fetchall()
    return jsonify([dict(r) for r in rows])

def _attendance_live_columns(db):
    """Return the live attendance table's column list minus auto
    fields. Used to build dynamic INSERT/UPDATE statements that
    survive schema drift."""
    try:
        rows = db.execute("PRAGMA table_info(attendance)").fetchall()
    except Exception:
        return []
    cols = []
    for r in rows:
        try:
            name = r[1]
        except Exception:
            try: name = r["name"]
            except Exception: continue
        if name and name not in ("id", "created_at"):
            cols.append(name)
    return cols


def _attendance_normalize_body(d):
    """Fold history-tolerant fields: date → ISO, group/name trimmed +
    whitespace-collapsed, status canonicalised through STATUS_REMAP."""
    out = dict(d or {})
    if "attendance_date" in out and out.get("attendance_date"):
        try:
            iso = _att_normalize_date(out["attendance_date"])
            if iso: out["attendance_date"] = iso
        except Exception:
            pass
    for k in ("group_name", "student_name"):
        if isinstance(out.get(k), str):
            out[k] = " ".join(out[k].split())
    if isinstance(out.get("status"), str) and out["status"]:
        out["status"] = STATUS_REMAP.get(out["status"], out["status"])
    return out


def _attendance_dynamic_insert(db, body):
    """INSERT one attendance row, whitelisting body keys against the
    live schema. Returns the new row id. Raises on SQL error."""
    cols = _attendance_live_columns(db)
    use_cols, use_vals = [], []
    for c in cols:
        if c in body:
            use_cols.append(c); use_vals.append(body.get(c))
    if not use_cols:
        # All-empty body — fall back to inserting just the date so PRAGMA
        # writes at least one column (avoids "no values" SQL error).
        use_cols = [c for c in ("attendance_date",) if c in cols]
        use_vals = [""]
    placeholders = ",".join(["?"] * len(use_cols))
    quoted = ",".join('"' + c + '"' for c in use_cols)
    sql = "INSERT INTO attendance (" + quoted + ") VALUES (" + placeholders + ")"
    db.execute(sql, tuple(use_vals))
    db.commit()
    try:
        return db.execute("SELECT last_insert_rowid()").fetchone()[0]
    except Exception:
        return None


def _attendance_dynamic_update(db, rid, body):
    """UPDATE only the columns present in body. No-op if body is
    empty for safety. Returns rowcount."""
    cols = _attendance_live_columns(db)
    set_cols, set_vals = [], []
    for c in cols:
        if c in body:
            set_cols.append('"' + c + '"=?'); set_vals.append(body.get(c))
    if not set_cols:
        return 0
    sql = "UPDATE attendance SET " + ",".join(set_cols) + " WHERE id=?"
    cur = db.execute(sql, tuple(set_vals) + (rid,))
    db.commit()
    try: return cur.rowcount
    except Exception: return 1


@app.route('/api/attendance', methods=['POST'])
@login_required
def api_attendance_add():
    """INSERT or UPDATE one attendance row. Whitelists body keys
    against the live schema so an extra NOT-NULL column on the prod
    DB doesn't poison the request. Logs exceptions to stderr."""
    d = request.get_json() or {}
    body = _attendance_normalize_body(d)
    db = get_db()
    try:
        sname = body.get("student_name") or ""
        sdate = body.get("attendance_date") or ""
        sgrp  = body.get("group_name") or ""
        existing = None
        if sname and sdate and sgrp:
            try:
                existing = db.execute(
                    "SELECT id FROM attendance "
                    "WHERE student_name=? AND attendance_date=? AND group_name=?",
                    (sname, sdate, sgrp),
                ).fetchone()
            except Exception:
                existing = None
        if existing:
            rid = existing[0] if not hasattr(existing, "keys") else existing["id"]
            try:
                _attendance_dynamic_update(db, rid, body)
            except Exception as ex:
                try: db.rollback()
                except Exception: pass
                import sys as _sys
                print("[attendance] update failed: " + str(ex), file=_sys.stderr)
                return jsonify({"ok": False, "error": str(ex)}), 400
            return jsonify({"ok": True, "id": rid, "updated": True})
        try:
            new_id = _attendance_dynamic_insert(db, body)
        except Exception as ex:
            try: db.rollback()
            except Exception: pass
            import sys as _sys
            print("[attendance] insert failed: " + str(ex), file=_sys.stderr)
            return jsonify({"ok": False, "error": str(ex)}), 400
        return jsonify({"ok": True, "id": new_id, "updated": False})
    except Exception as ex:
        try: db.rollback()
        except Exception: pass
        import sys as _sys
        print("[attendance] handler crashed: " + str(ex), file=_sys.stderr)
        return jsonify({"ok": False, "error": str(ex)}), 400


@app.route('/api/attendance/<int:rid>', methods=['PUT'])
@login_required
def api_attendance_update(rid):
    d = request.get_json() or {}
    body = _attendance_normalize_body(d)
    db = get_db()
    try:
        _attendance_dynamic_update(db, rid, body)
        # Echo the post-normalisation row so per-cell editors can sync
        # the canonical value (status remap, ISO date, trimmed names)
        # back into the cell without a full table reload.
        row = db.execute("SELECT * FROM attendance WHERE id=?", (rid,)).fetchone()
        return jsonify({"ok": True, "row": dict(row) if row else None})
    except Exception as ex:
        try: db.rollback()
        except Exception: pass
        import sys as _sys
        print("[attendance] PUT failed: " + str(ex), file=_sys.stderr)
        return jsonify({"ok": False, "error": str(ex)}), 400

