@app.route('/api/attendance/by-date-group', methods=['GET'])
@login_required
def api_attendance_by_date_group():
    date = request.args.get('date', '')
    group = request.args.get('group', '')
    include_inactive = (request.args.get('include_inactive') or '') in ('1', 'true', 'yes')
    # date or group (or both) may be the sentinel '__all__' meaning "drop that
    # filter". Empty group is treated like __all__ for backwards-compatibility.
    all_dates  = (date  == '__all__')
    all_groups = (group == '__all__' or group == '')
    if not date and not all_dates:
        return jsonify({"rows": []})
    db = get_db()
    base = (
        "SELECT a.id, a.attendance_date, a.group_name, a.student_name, a.status, "
        "       a.message_status, s.whatsapp, ml.last_sent "
        "  FROM attendance a "
        "  LEFT JOIN students s ON s.student_name = a.student_name "
        "  LEFT JOIN ( "
        "      SELECT student_name, MAX(sent_at) AS last_sent "
        "        FROM message_log "
        "       GROUP BY student_name "
        "  ) ml ON ml.student_name = a.student_name "
    )
    # Active-only filter (رصد الغياب per-group + جميع المجموعات unified
    # list + the absence-messaging modal all consume this endpoint and
    # should never surface unregistered students in attendance flows).
    # Defensive: resolve the column + value here directly with hardcoded
    # fallbacks so a cleared /settings entry never silently disables
    # the gate. ?include_inactive=1 opts out for audit / debugging only.
    extra_filter = ''
    extra_params = ()
    if not include_inactive:
        act_col = (get_setting('students', 'active_column', 'registration_term2_2026') or '').strip() \
                  or 'registration_term2_2026'
        act_val = (get_setting('students', 'active_value',  'تم التسجيل') or '').strip() \
                  or 'تم التسجيل'
        if not _is_safe_ident(act_col):
            act_col = 'registration_term2_2026'
        try:
            _live = {r[1] for r in db.execute("PRAGMA table_info(students)").fetchall()}
        except Exception:
            _live = set()
        if act_col in _live:
            extra_filter = " AND TRIM(COALESCE(s.\"" + act_col + "\",'')) = ?"
            extra_params = (act_val,)
    # Cap the result so "all dates + all groups" doesn't ship the entire
    # attendance history in one response.
    tail = " ORDER BY a.attendance_date DESC, a.group_name, a.student_name LIMIT 1000"
    if all_dates and all_groups:
        where = "WHERE 1=1"
        params = ()
    elif all_dates:
        where = "WHERE a.group_name=?"
        params = (group,)
    elif all_groups:
        where = "WHERE a.attendance_date=?"
        params = (date,)
    else:
        where = "WHERE a.attendance_date=? AND a.group_name=?"
        params = (date, group)
    rows = db.execute(base + where + extra_filter + tail,
                      params + extra_params).fetchall()
    return jsonify({"rows": [dict(r) for r in rows]})


@app.route('/api/attendance/by-date-summary', methods=['GET'])
@login_required
def api_attendance_by_date_summary():
    """For the given date, return the list of groups whose schedule
    includes that weekday (under the active center mode), each
    annotated with whether attendance has been recorded on that date
    plus per-group counts (total, absent, late). Drives the additive
    summary block above the unified absentees list.

    Reuses the same day-matching helpers (_extract_days_from_row +
    _grp_extract_days) the group-search facet uses, and the same
    mode + mode_exceptions handling _teacher_mode_filtered_groups
    uses, so what shows here matches what the rest of the app
    considers "scheduled today"."""
    import datetime as _dt
    raw_date = (request.args.get('date') or '').strip()
    iso = _att_normalize_date(raw_date) if raw_date else ''
    if not iso:
        return jsonify({"ok": False, "error": "date is required"}), 400
    try:
        y, m, d = [int(p) for p in iso.split('-')]
        py_weekday = _dt.date(y, m, d).weekday()  # Mon=0 .. Sun=6
    except Exception:
        return jsonify({"ok": False, "error": "invalid date"}), 400
    # Map Python weekday → canonical Arabic day name (matches _GRP_AR_DAYS).
    _PY_TO_AR_DAY = {
        0: "الإثنين", 1: "الثلاثاء", 2: "الأربعاء",
        3: "الخميس", 4: "الجمعة", 5: "السبت", 6: "الأحد",
    }
    target_day = _PY_TO_AR_DAY.get(py_weekday, "")

    db = get_db()
    mode = _get_center_mode(db)

    # Per-group mode exceptions (same handling as the teacher attendance
    # filter so a group hidden in this mode also doesn't surface here).
    try:
        exc_rows = db.execute(
            "SELECT key_name, mode FROM mode_exceptions WHERE scope='group'"
        ).fetchall()
    except Exception:
        exc_rows = []
    exc_map = {}
    for r in exc_rows:
        rd = dict(r) if hasattr(r, "keys") else {"key_name": r[0], "mode": r[1]}
        kn = (rd.get("key_name") or "").strip()
        md = (rd.get("mode")     or "").strip()
        if kn and md:
            exc_map[kn] = md

    # Prime the authoritative-days resolver and add its column to the
    # SELECT so Strategy 0 in _extract_days_from_row can pick it up.
    days_col = _groups_days_column(db)
    extra_days = ('"' + days_col + '", ') if days_col != 'study_days' else ''
    try:
        rows = db.execute(
            "SELECT " + extra_days + "group_name, teacher_name, study_days, study_time, "
            "       ramadan_time, online_time "
            "FROM student_groups "
            "WHERE group_name IS NOT NULL AND TRIM(group_name) <> ''"
        ).fetchall()
    except Exception:
        rows = []

    scheduled = []
    for r in rows:
        rd = dict(r)
        gname = (rd.get("group_name") or "").strip()
        if not gname:
            continue
        # Per-group mode override: only show if the group's exception
        # mode equals the active center mode.
        ex = exc_map.get(gname)
        if ex and ex != mode:
            continue
        # Day match — substring search of canonical day names against
        # whatever separator format the group's study_days uses.
        days_raw = _extract_days_from_row(rd) or (rd.get("study_days") or "")
        if target_day not in _grp_extract_days(days_raw):
            continue
        # Pick the time field that matches the active mode (display only;
        # we still include the group whether or not the field is set).
        if mode == "أونلاين":
            sched_time = (rd.get("online_time")  or rd.get("study_time") or "").strip()
        elif mode == "رمضان":
            sched_time = (rd.get("ramadan_time") or rd.get("study_time") or "").strip()
        else:
            sched_time = (rd.get("study_time") or "").strip()
        scheduled.append({
            "name":          gname,
            "teacher":       (rd.get("teacher_name") or "").strip(),
            "schedule_time": sched_time,
        })

    scheduled.sort(key=lambda g: g["name"])

    # Per-group attendance counts on the target date. Loose date match
    # via _att_normalize_date so legacy rows in mixed formats
    # (D/M/YYYY, with the Arabic era marker, etc.) still resolve.
    rec = {}
    # student_names that already have an attendance record on this
    # date, keyed by trimmed group_name. Drives the completeness
    # check ("تام / غير تام / لم يُرصد").
    recorded_names_by_group = {}
    try:
        att_rows = db.execute(
            "SELECT group_name, status, attendance_date, student_name FROM attendance"
        ).fetchall()
        for r in att_rows:
            rd = dict(r)
            if _att_normalize_date(rd.get("attendance_date") or "") != iso:
                continue
            g = (rd.get("group_name") or "").strip()
            st = (rd.get("status") or "").strip()
            if not g:
                continue
            entry = rec.setdefault(g, {"total": 0, "absent": 0, "late": 0})
            entry["total"] += 1
            if st == "غائب":
                entry["absent"] += 1
            elif st == "متأخر":
                entry["late"] += 1
            sn = (rd.get("student_name") or "").strip()
            if sn:
                recorded_names_by_group.setdefault(g, set()).add(sn)
    except Exception:
        rec = {}
        recorded_names_by_group = {}

    # ── Completeness check (additive) ──────────────────────────────
    # For each scheduled group, look up the REGISTERED roster (same
    # active-only filter the teacher attendance flow uses) and
    # compute:
    #   state="تام"      → every registered student has a record;
    #   state="غير تام"  → some registered students are missing —
    #                       missing_students[] lists their names;
    #   state="لم يُرصد"  → zero records for the group on this date.
    # Reuses the configured group-link columns (in-person + online)
    # so a student linked via group_online still counts. Active-
    # column resolution mirrors the teacher attendance fix so an
    # admin cleared /settings entry doesn't silently disable the gate.
    in_person_col = get_setting('attendance', 'student_group_column',         'group_name_student')
    online_col    = get_setting('attendance', 'student_online_group_column',  'group_online')
    if not _is_safe_ident(in_person_col): in_person_col = 'group_name_student'
    if not _is_safe_ident(online_col):    online_col    = 'group_online'
    try:
        s_live = {r[1] for r in db.execute("PRAGMA table_info(students)").fetchall()}
    except Exception:
        s_live = set()
    has_online = (online_col in s_live and online_col != in_person_col)
    act_col_eff = (get_setting('students', 'active_column', 'registration_term2_2026') or '').strip() \
                  or 'registration_term2_2026'
    if not _is_safe_ident(act_col_eff): act_col_eff = 'registration_term2_2026'
    act_val_eff = (get_setting('students', 'active_value',  'تم التسجيل') or '').strip() \
                  or 'تم التسجيل'
    has_active_col = (act_col_eff in s_live)

    # Build a single-shot { group_name → [registered_student_names] }
    # by selecting once and splitting in Python — cheaper than one
    # query per group.
    registered_by_group = {}
    try:
        cols_sel = '"' + in_person_col + '"'
        if has_online:
            cols_sel += ', "' + online_col + '"'
        sql = ('SELECT student_name, ' + cols_sel + ' FROM students '
               'WHERE student_name IS NOT NULL AND TRIM(student_name) <> \'\'')
        params = ()
        if has_active_col:
            sql += ' AND TRIM(COALESCE("' + act_col_eff + '", \'\')) = ?'
            params = (act_val_eff,)
        srows = db.execute(sql, params).fetchall()
        for sr in srows:
            srd = dict(sr)
            sn = (srd.get('student_name') or '').strip()
            if not sn: continue
            ip = (srd.get(in_person_col) or '').strip() if in_person_col else ''
            on = (srd.get(online_col) or '').strip() if has_online and online_col else ''
            for grp in {ip, on} - {''}:
                registered_by_group.setdefault(grp, []).append(sn)
    except Exception:
        registered_by_group = {}

    out = []
    for g in scheduled:
        rc = rec.get(g["name"]) or {"total": 0, "absent": 0, "late": 0}
        registered = registered_by_group.get(g["name"], [])
        recorded_set = recorded_names_by_group.get(g["name"], set())
        # Missing names: registered who don't appear in recorded_set.
        # Whitespace-tolerant comparison.
        rec_norm = {(n or '').strip() for n in recorded_set}
        missing = [n for n in registered if (n or '').strip() not in rec_norm]
        n_reg = len(registered)
        n_rec = len([n for n in registered if (n or '').strip() in rec_norm])
        if n_reg == 0:
            # No registered students at all — fall back to the bare
            # recorded? indicator so the row isn't silently dropped.
            state = "تام" if rc["total"] > 0 else "لم يُرصد"
        elif n_rec == 0:
            state = "لم يُرصد"
        elif n_rec >= n_reg:
            state = "تام"
        else:
            state = "غير تام"
        out.append({
            "name":             g["name"],
            "teacher":          g["teacher"],
            "schedule_time":    g["schedule_time"],
            "recorded":         bool(rec.get(g["name"])),
            "total":            rc["total"],
            "absent":           rc["absent"],
            "late":             rc["late"],
            # New fields driving the completeness UI.
            "state":            state,
            "registered_count": n_reg,
            "recorded_count":   n_rec,
            "missing_count":    max(0, n_reg - n_rec),
            "missing_students": missing,
        })

    # ── Anomaly detection (additive) ────────────────────────────────
    # A group is "anomalous" on this date when attendance was recorded
    # for it BUT the date's day-of-week is not in its scheduled days.
    # Catches data-entry mistakes like recording الإثنين attendance on
    # a Sunday. Reuses the same _grp_extract_days helper the schedule
    # match above uses, so what counts as "scheduled days" for a group
    # is identical to what the summary block considers scheduled.
    #
    # The schema only carries study_days (online_days was dropped in
    # the 2026-Q1 cleanup, ramadan_days never existed) so the day set
    # is the same regardless of mode — only the *time* column differs
    # per mode. Mode-exception groups: if the group is overridden to
    # a mode that ISN'T the active one, we still flag wrong-day
    # records for it, so an admin can spot stale records left over
    # from before the override flipped.
    group_index = {}  # gname → authoritative days raw
    try:
        idx_rows = db.execute(
            "SELECT " + extra_days + "group_name, study_days FROM student_groups"
        ).fetchall()
        for r in idx_rows:
            rd = dict(r)
            gn = (rd.get("group_name") or "").strip()
            if gn:
                # _row_days_authoritative prefers the user-added column
                # (when distinct from study_days) and falls back per-row
                # to study_days when the new column is empty.
                group_index[gn] = _row_days_authoritative(rd, days_col)
    except Exception:
        pass

    anomalies = []
    for gname in sorted(rec.keys()):
        if gname not in group_index:
            # Attendance was recorded for a group that no longer
            # exists in student_groups (renamed / deleted). That's a
            # different anomaly — surface it so the admin notices.
            anomalies.append({
                "name":           gname,
                "scheduled_days": "",
                "selected_day":   target_day,
                "reason":         "missing_group",
                "total":          rec[gname]["total"],
            })
            continue
        days_raw = group_index[gname]
        days_set = _grp_extract_days(days_raw)
        if target_day and target_day not in days_set:
            anomalies.append({
                "name":           gname,
                "scheduled_days": days_raw,
                "selected_day":   target_day,
                "reason":         "wrong_day",
                "total":          rec[gname]["total"],
            })

    return jsonify({
        "ok": True,
        "date": iso,
        "day": target_day,
        "mode": mode,
        "groups": out,
        "totals": {
            "scheduled":    len(out),
            "recorded":     sum(1 for g in out if g["recorded"]),
            "not_recorded": sum(1 for g in out if not g["recorded"]),
        },
        "anomalies": anomalies,
    })


@app.route('/api/attendance/<int:rid>/mark-sent', methods=['POST'])
@login_required
def api_attendance_mark_sent(rid):
    db = get_db()
    try:
        db.execute("UPDATE attendance SET message_status=? WHERE id=?",
                   ("تم الإرسال", rid))
        db.commit()
        return jsonify({"ok": True})
    except Exception as ex:
        return jsonify({"ok": False, "error": str(ex)}), 400

