@app.route("/groups")
@login_required
def groups():
    return GROUPS_HTML

@app.route("/api/groups", methods=["GET"])
@login_required
def api_groups_get():
    db = get_db()
    rows = db.execute("SELECT * FROM student_groups ORDER BY id ASC").fetchall()
    return jsonify({"groups": [dict(r) for r in rows]})

def _student_groups_writable_cols(db):
    # Reflect the live schema so a user who has deleted a column via the UI
    # (e.g. session_duration) doesn't break every subsequent add/update.
    cols = [r[1] for r in db.execute("PRAGMA table_info(student_groups)").fetchall()]
    return [c for c in cols if c not in ("id", "created_at")]

@app.route("/api/groups", methods=["POST"])
@login_required
def api_groups_add():
    d = request.get_json() or {}
    db = get_db()
    try:
        cols = _student_groups_writable_cols(db)
        placeholders = ",".join(["?"] * len(cols))
        values = tuple(d.get(c) for c in cols)
        db.execute("INSERT INTO student_groups (" + ",".join(cols) + ") VALUES (" + placeholders + ")", values)
        db.commit()
        return jsonify({"ok": True})
    except Exception as ex:
        return jsonify({"ok": False, "error": str(ex)}), 400

@app.route("/api/groups/<int:gid>", methods=["PUT"])
@login_required
def api_groups_update(gid):
    d = request.get_json() or {}
    db = get_db()
    try:
        # Partial-update friendly: only touch columns the caller actually
        # sent. The pencil-button modal sends every field, so its
        # behaviour is unchanged; per-cell editors send a single field
        # and won't NULL the rest of the row.
        cols = [c for c in _student_groups_writable_cols(db) if c in d]
        if not cols:
            return jsonify({"ok": True})
        set_clause = ",".join([c + "=?" for c in cols])
        values = tuple(d.get(c) for c in cols) + (gid,)
        db.execute("UPDATE student_groups SET " + set_clause + " WHERE id=?", values)
        db.commit()
        return jsonify({"ok": True})
    except Exception as ex:
        return jsonify({"ok": False, "error": str(ex)}), 400

@app.route("/api/groups/<int:gid>", methods=["DELETE"])
@login_required
def api_groups_delete(gid):
    try:
        db = get_db()
        db.execute("DELETE FROM student_groups WHERE id=?", (gid,))
        db.commit()
        return jsonify({"ok": True})
    except Exception as ex:
        return jsonify({"ok": False, "error": str(ex)}), 400

@app.route("/api/groups/cleanup-empty", methods=["POST"])
@login_required
def api_groups_cleanup_empty():
    try:
        db = get_db()
        cur = db.execute("DELETE FROM student_groups WHERE group_name IS NULL OR TRIM(group_name) = ''")
        deleted = cur.rowcount if cur.rowcount is not None else 0
        db.commit()
        return jsonify({"ok": True, "deleted": deleted})
    except Exception as ex:
        return jsonify({"ok": False, "error": str(ex)}), 400

@app.route("/api/groups-students", methods=["GET"])
@login_required
def api_groups_students():
    """Group → student roster. The dropdown is populated from BOTH the
    in-person group column AND the online group column on `students`,
    UNION-ed and sorted, so an online-only group shows up in the list.
    Both column names are configurable via the settings table:
        attendance.student_group_column       (default: group_name_student)
        attendance.student_online_group_column (default: group_online)

    By default only ACTIVE students contribute. Pass ?include_inactive=1
    to count every student regardless of registration status."""
    db = get_db()
    include_inactive = (request.args.get("include_inactive") or "") in ("1", "true", "yes")
    act_frag, act_val = _active_students_filter()

    # Resolve configurable column names with _is_safe_ident validation
    # (the helper itself is unvalidated by design — see CLAUDE.md).
    in_person_col = get_setting('attendance', 'student_group_column', 'group_name_student')
    online_col    = get_setting('attendance', 'student_online_group_column', 'group_online')
    if not _is_safe_ident(in_person_col):
        in_person_col = 'group_name_student'
    if not _is_safe_ident(online_col):
        online_col = 'group_online'

    # Verify the columns actually exist; if either is missing fall back
    # to the in-person column alone so a misconfigured DB still works.
    try:
        live_cols = {r[1] for r in db.execute("PRAGMA table_info(students)").fetchall()}
    except Exception:
        live_cols = set()
    has_online = (online_col in live_cols) and (online_col != in_person_col)

    def _q_distinct(col):
        sql = ('SELECT DISTINCT "' + col + '" FROM students '
               'WHERE "' + col + '" IS NOT NULL AND "' + col + '" <> \'\'')
        params = ()
        if act_frag and not include_inactive:
            sql += " AND " + act_frag
            params = (act_val,)
        return db.execute(sql, params).fetchall()

    group_set = set()
    for r in _q_distinct(in_person_col):
        if r[0]: group_set.add(r[0])
    if has_online:
        for r in _q_distinct(online_col):
            if r[0]: group_set.add(r[0])

    groups_sorted = sorted(group_set)

    # Fetch the per-group student list once per group. Match a student to
    # a group if EITHER the in-person OR the online column matches.
    if has_online:
        students_sql = ('SELECT id, student_name, personal_id, whatsapp FROM students '
                        'WHERE ("' + in_person_col + '" = ? OR "' + online_col + '" = ?)')
    else:
        students_sql = ('SELECT id, student_name, personal_id, whatsapp FROM students '
                        'WHERE "' + in_person_col + '" = ?')
    if act_frag and not include_inactive:
        students_sql += " AND " + act_frag
    students_sql += " ORDER BY student_name"

    out = {}
    for gname in groups_sorted:
        if has_online:
            params = [gname, gname]
        else:
            params = [gname]
        if act_frag and not include_inactive:
            params.append(act_val)
        students = db.execute(students_sql, tuple(params)).fetchall()
        out[gname] = [dict(s) for s in students]
    return jsonify(out)

def _att_normalize_date(s):
    """Normalise any date representation the app has ever stored to ISO
    YYYY-MM-DD. Handles:
      - already ISO: "2026-04-01"
      - D/M/YYYY:   "9/2/2026"
      - mixed sep:  "31/1-2026" (slash then dash)
      - D-M-YYYY:   "09-02-2026"
      - Y/M/D:      "2026/02/09"
      - trailing Arabic era marker like "م" or Latin punctuation
    Any value the parser cannot interpret is returned unchanged so we
    never lose data on a surprise format; use _att_normalize_ar on free
    text."""
    import re as _re_local
    if not s:
        return ""
    s = str(s).strip()
    if not s:
        return ""
    nums = _re_local.findall(r"\d+", s)
    if len(nums) < 3:
        return s
    if len(nums[0]) == 4:
        y, m, d = nums[0], nums[1], nums[2]
    elif len(nums[-1]) == 4:
        d, m, y = nums[0], nums[1], nums[-1]
    else:
        d, m, y = nums[0], nums[1], nums[2]
        if len(y) == 2:
            y = ("20" + y) if int(y) < 70 else ("19" + y)
    try:
        iy, im, id_ = int(y), int(m), int(d)
        if not (1 <= im <= 12 and 1 <= id_ <= 31):
            return s
        return "%04d-%02d-%02d" % (iy, im, id_)
    except Exception:
        return s


def _att_normalize_ar(s):
    """Loose Arabic string normalisation used to match imported roster names
    against attendance rows: trim, collapse whitespace runs, lowercase,
    fold alef/yeh/teh-marbouta variants, drop tashkeel."""
    if not s:
        return ""
    s = str(s).strip().lower()
    # alef family -> bare alef
    for ch in ("أ", "إ", "آ", "ٱ"):
        s = s.replace(ch, "ا")
    s = s.replace("ة", "ه")  # teh marbouta -> heh
    s = s.replace("ى", "ي")  # alef maksura -> yeh
    out = []
    prev_space = False
    for ch in s:
        c = ord(ch)
        if 0x064B <= c <= 0x065F:   # strip tashkeel
            continue
        if ch.isspace():
            if prev_space:
                continue
            prev_space = True
            out.append(" ")
        else:
            prev_space = False
            out.append(ch)
    return "".join(out).strip()


VALID_CENTER_MODES = ("\u062D\u0636\u0648\u0631\u064A", "\u0623\u0648\u0646\u0644\u0627\u064A\u0646", "\u0631\u0645\u0636\u0627\u0646")


def _center_mode_default():
    return "\u062D\u0636\u0648\u0631\u064A"


def _get_center_mode(db):
    """Read the active center mode from settings; default حضوري."""
    try:
        v = get_setting("system", "center_mode", _center_mode_default())
    except Exception:
        v = _center_mode_default()
    v = (v or "").strip()
    return v if v in VALID_CENTER_MODES else _center_mode_default()


def _set_center_mode(db, mode):
    mode = (mode or "").strip()
    if mode not in VALID_CENTER_MODES:
        return False
    try:
        cur = db.execute(
            "UPDATE settings SET value=? WHERE page=? AND component=?",
            (mode, "system", "center_mode"),
        )
        if cur.rowcount == 0:
            db.execute(
                "INSERT INTO settings(page,component,label,value) VALUES(?,?,?,?)",
                ("system", "center_mode", "\u062D\u0627\u0644\u0629 \u0627\u0644\u0645\u0631\u0643\u0632", mode),
            )
        db.commit()
        return True
    except Exception:
        return False


def _lookup_mode_exception(db, student_id):
    """Return the override mode for this student, or None. Priority:
    student-level exception → group-level exception → None."""
    try:
        srow = db.execute(
            "SELECT student_name, group_name_student, group_online FROM students WHERE id=?",
            (student_id,),
        ).fetchone()
    except Exception:
        srow = None
    if not srow:
        return None
    sd = dict(srow) if hasattr(srow, "keys") else {
        "student_name": srow[0],
        "group_name_student": srow[1],
        "group_online": srow[2],
    }
    sname = (sd.get("student_name") or "").strip()
    if sname:
        try:
            r = db.execute(
                "SELECT mode FROM mode_exceptions WHERE scope=\'student\' AND TRIM(key_name)=TRIM(?) LIMIT 1",
                (sname,),
            ).fetchone()
        except Exception:
            r = None
        if r and r[0]:
            return str(r[0])
    for gkey in ("group_name_student", "group_online"):
        gn = (sd.get(gkey) or "").strip()
        if not gn: continue
        try:
            r = db.execute(
                "SELECT mode FROM mode_exceptions WHERE scope=\'group\' AND TRIM(key_name)=TRIM(?) LIMIT 1",
                (gn,),
            ).fetchone()
        except Exception:
            r = None
        if r and r[0]:
            return str(r[0])
    return None


def _resolve_center_class_meta(db, mode, sid):
    """For a student id + active center mode, return:
       { class_duration, class_type, group, warning? }.
       Honors per-student / per-group exceptions from the
       mode_exceptions table — they override the passed-in mode."""
    if mode not in VALID_CENTER_MODES:
        mode = _center_mode_default()
    override = _lookup_mode_exception(db, sid)
    if override and override in VALID_CENTER_MODES:
        mode = override
    out = {"class_duration": "", "class_type": mode, "group": "",
           "mode": mode, "warning": ""}
    try:
        s = db.execute(
            "SELECT group_name_student, group_online FROM students WHERE id=?",
            (sid,),
        ).fetchone()
    except Exception:
        s = None
    if not s:
        return out
    sd = dict(s) if hasattr(s, "keys") else {"group_name_student": s[0], "group_online": s[1]}
    # Pick the group key per mode.
    if mode == "\u0623\u0648\u0646\u0644\u0627\u064A\u0646":
        gname = (sd.get("group_online") or "").strip()
        if not gname:
            out["warning"] = ("\u26A0 \u0644\u0627 \u064A\u0648\u062C\u062F \u0631\u0642\u0645 "
                              "\u0645\u062C\u0645\u0648\u0639\u0629 \u0623\u0648\u0646\u0644\u0627\u064A\u0646 "
                              "\u0644\u0647\u0630\u0627 \u0627\u0644\u0637\u0627\u0644\u0628 \u2014 "
                              "\u064A\u0631\u062C\u0649 \u0627\u0644\u062A\u062E\u0635\u064A\u0635 "
                              "\u064A\u062F\u0648\u064A\u0627\u064B")
            return out
    else:
        gname = (sd.get("group_name_student") or "").strip()
    out["group"] = gname
    if not gname:
        return out
    # Look up the duration. For Ramadan, prefer a hypothetical
    # ramadan-specific column if the admin ever adds one; otherwise
    # fall back to session_duration. session_minutes_normal is a
    # secondary fallback — some legacy groups use it.
    try:
        live_cols = {r[1] for r in db.execute("PRAGMA table_info(student_groups)").fetchall()}
    except Exception:
        live_cols = set()
    cand_cols = []
    if mode == "\u0631\u0645\u0636\u0627\u0646":
        for c in ("ramadan_session_duration", "ramadan_duration", "ramadan_time", "session_duration", "session_minutes_normal"):
            if c in live_cols: cand_cols.append(c)
    else:
        for c in ("session_duration", "session_minutes_normal"):
            if c in live_cols: cand_cols.append(c)
    for col in cand_cols:
        try:
            row = db.execute(
                "SELECT \"" + col + "\" FROM student_groups "
                "WHERE TRIM(group_name)=TRIM(?) LIMIT 1",
                (gname,),
            ).fetchone()
        except Exception:
            row = None
        if row and row[0] is not None and str(row[0]).strip():
            out["class_duration"] = str(row[0]).strip()
            break
    if not out["class_duration"]:
        out["warning"] = ("\u26A0 \u0644\u0627 \u062A\u0648\u062C\u062F \u0645\u062F\u0629 "
                          "\u0645\u062D\u062F\u062F\u0629 \u0644\u0644\u0645\u062C\u0645\u0648\u0639\u0629 "
                          "\u0641\u064A \u062C\u062F\u0648\u0644 \u0627\u0644\u0645\u062C\u0645\u0648\u0639\u0627\u062A")
    return out


@app.route("/api/center/exceptions", methods=["GET"])
@admin_required
def api_center_exceptions_list():
    db = get_db()
    try:
        rows = db.execute(
            "SELECT id, scope, key_name, mode, created_at "
            "FROM mode_exceptions ORDER BY scope, key_name"
        ).fetchall()
    except Exception:
        rows = []
    return jsonify({"ok": True, "exceptions": [dict(r) for r in rows]})


@app.route("/api/center/exceptions", methods=["POST"])
@admin_required
def api_center_exceptions_add():
    user = session.get("user") or {}
    if (user.get("role") or "").strip().lower() != "admin":
        return jsonify({"ok": False, "error": "forbidden"}), 403
    d = request.get_json() or {}
    scope = (d.get("scope") or "").strip().lower()
    key   = (d.get("key_name") or "").strip()
    mode  = (d.get("mode") or "").strip()
    if scope not in ("group", "student"):
        return jsonify({"ok": False, "error": "scope must be group or student"}), 400
    if mode not in VALID_CENTER_MODES:
        return jsonify({"ok": False, "error": "invalid mode"}), 400
    if not key:
        return jsonify({"ok": False, "error": "key_name required"}), 400
    db = get_db()
    try:
        cur = db.execute(
            "UPDATE mode_exceptions SET mode=? WHERE scope=? AND key_name=?",
            (mode, scope, key),
        )
        if cur.rowcount == 0:
            db.execute(
                "INSERT INTO mode_exceptions(scope, key_name, mode) VALUES(?,?,?)",
                (scope, key, mode),
            )
        db.commit()
        return jsonify({"ok": True})
    except Exception as ex:
        return jsonify({"ok": False, "error": str(ex)}), 400


@app.route("/api/center/exceptions/<int:eid>", methods=["DELETE"])
@admin_required
def api_center_exceptions_delete(eid):
    user = session.get("user") or {}
