def _drive_build_header_lookup(table, db):
    """Build a folded-Arabic-header → english-col-key lookup for one of
    the Drive-import tables. Fuses three sources, all normalised via
    _grp_norm so ا/أ/إ/آ/ى/ة/diacritic/NBSP variants match symmetrically:

      1. Static aliases from _DRIVE_SHEET_MAP[table] (covers common
         alt-phrasings + the parent-link column to deliberately skip).
      2. Live labels from the table's *_col_labels rows, HTML-entity-
         decoded. Auto-adapts to whatever Arabic label the admin set
         in /database, even if it differs from the seed text.
      3. The English col_key itself — so a user who pastes the bare
         column name (e.g. "group_name") into a sheet header still
         matches.

    Live labels OVERRIDE static aliases when both fold to the same key,
    so an admin rename in /database is respected without a code change.
    Returns whatever it managed to build on any DB error so the caller
    falls back to static-only matching."""
    import html as _html
    lookup = {}
    static = _DRIVE_SHEET_MAP.get(table) or {}
    for k, v in static.items():
        folded = _grp_norm(k)
        if folded:
            lookup[folded] = v
    lbl_tbl = IMPORT_LABEL_TABLES.get(table)
    if lbl_tbl and db is not None:
        try:
            for r in db.execute(
                "SELECT col_key, col_label FROM " + lbl_tbl
            ).fetchall():
                col_key   = r[0] if hasattr(r, "__getitem__") else None
                col_label = r[1] if hasattr(r, "__getitem__") else None
                if not col_key:
                    continue
                col_key = str(col_key)
                if col_label:
                    decoded = _html.unescape(str(col_label))
                    folded  = _grp_norm(decoded)
                    if folded:
                        lookup[folded] = col_key
                # Also let the user paste the English col_key directly.
                key_folded = _grp_norm(col_key)
                if key_folded and key_folded not in lookup:
                    lookup[key_folded] = col_key
        except Exception:
            pass
    return lookup


def _drive_fetch_xlsx(url):
    """Fetch a Google Sheets published workbook as raw XLSX bytes.

    Accepts the `/pubhtml` URL produced by File -> Publish to web and
    rewrites it to `/pub?output=xlsx` so Google returns the binary.
    Stdlib only (urllib.request) -- no new dependency. 60s timeout.
    Raises RuntimeError on any failure so the endpoint can surface one
    Arabic error to the user instead of leaking a stacktrace. Pure:
    no DB, no Flask context, no module globals.
    """
    import urllib.request, urllib.error
    if not url or not isinstance(url, str):
        raise RuntimeError("missing drive workbook url")
    base = url.split("?", 1)[0].split("#", 1)[0]
    if base.endswith("/pubhtml"):
        xurl = base[: -len("/pubhtml")] + "/pub?output=xlsx"
    elif base.endswith("/pub"):
        xurl = base + "?output=xlsx"
    else:
        sep = "&" if "?" in url else "?"
        xurl = url + sep + "output=xlsx"
    try:
        req = urllib.request.Request(xurl, headers={"User-Agent": "mindx-portal/1.0"})
        with urllib.request.urlopen(req, timeout=60) as resp:
            status = getattr(resp, "status", 200)
            if status != 200:
                raise RuntimeError("http " + str(status))
            data = resp.read()
    except urllib.error.URLError as ex:
        raise RuntimeError("network error: " + str(getattr(ex, "reason", ex))[:120])
    except RuntimeError:
        raise
    except Exception as ex:
        raise RuntimeError("fetch failed: " + str(ex)[:120])
    if not data or len(data) < 4 or data[:2] != b"PK":
        raise RuntimeError(
            "response is not an xlsx workbook (sheet may be unpublished or url wrong)"
        )
    return data


# Per-table list of acceptable worksheet-name variants. _drive_resolve_sheet_name
# walks this list (after the configured name + a folded-equality try) so
# admins can rename their Drive sheets within reason without breaking
# imports. _grp_norm folds ا/أ/إ/آ/ى/ة/diacritic/NBSP variants, so each
# entry below only needs ONE spelling per family.
_DRIVE_SHEET_VARIANTS = {
    "students": [
        "الصفحة الرئيسية لمعلومات الطلبة",
        "قاعدة بيانات الطلبة",
        "بيانات الطلبة",
        "الطلبة",
        "الطلاب",
        "students",
    ],
    "student_groups": [
        "معلومات المجموعات (يدوي)",
        "معلومات المجموعات",
        "المجموعات",
        "groups",
        "student_groups",
    ],
    "attendance": [
        "سجل الغياب",
        "الغياب",
        "attendance",
    ],
    "payment_log": [
        "تفاصيل الدفع",
        "سجل الدفع",
        "الدفع",
        "payment_log",
        "paylog",
    ],
}


def _drive_resolve_sheet_name(sheet_name, available_titles, table):
    """Resolve `sheet_name` against the actual worksheet titles in the
    workbook. Returns (resolved_title, fallback_used: bool) or raises
    RuntimeError on no/ambiguous match.

    Resolution order (each step folded via _grp_norm where noted):
      1. Exact match (current behaviour, no fallback flag).
      2. Folded-equality match against the configured name.
      3. Folded-equality match against _DRIVE_SHEET_VARIANTS[table].
      4. Folded substring match (target contained in title or vice
         versa) — only used when EXACTLY one title qualifies, to
         avoid silently picking the wrong sheet.

    Steps 2–4 set fallback_used=True so the response payload can show
    that the configured name didn't match exactly. Ambiguous substring
    match (multiple candidates) raises a RuntimeError that lists the
    candidates so the admin can pick.
    """
    if sheet_name in available_titles:
        return sheet_name, False
    folded_titles = {}
    for t in available_titles:
        folded = _grp_norm(t)
        if folded and folded not in folded_titles:
            folded_titles[folded] = t
    target_folded = _grp_norm(sheet_name)
    if target_folded and target_folded in folded_titles:
        return folded_titles[target_folded], True
    for v in _DRIVE_SHEET_VARIANTS.get(table, []):
        v_folded = _grp_norm(v)
        if v_folded and v_folded in folded_titles:
            return folded_titles[v_folded], True
    if target_folded:
        candidates = []
        for ft, original in folded_titles.items():
            if target_folded in ft or ft in target_folded:
                candidates.append(original)
        # Dedupe while preserving order.
        seen = set(); uniq = []
        for c in candidates:
            if c not in seen:
                seen.add(c); uniq.append(c)
        if len(uniq) == 1:
            return uniq[0], True
        if len(uniq) > 1:
            raise RuntimeError(
                "sheet ambiguous: multiple sheets match \""
                + str(sheet_name) + "\": " + ", ".join(uniq)
            )
    raise RuntimeError(
        "sheet not found: " + str(sheet_name)
        + " (available: " + ", ".join(available_titles) + ")"
    )


def _drive_extract_rows(table, xlsx_bytes, sheet_name, db=None):
    """Parse the named sheet from the in-memory XLSX bytes and return
    `(rows, unmatched_headers, resolved_sheet_name)`.

    rows: list of row-dicts keyed by the English field names found via
      `_drive_build_header_lookup` (static aliases + live *_col_labels +
      raw col_key, all folded via _grp_norm so spelling variants match).
    unmatched_headers: list of distinct sheet headers that didn't map
      to any target — surfaced to the API response so the admin can
      either fix the sheet header or rename the DB column label.
    resolved_sheet_name: the actual worksheet title that was opened.
      Equal to `sheet_name` on the exact-match path; equal to the
      fuzzy-resolved title (via _drive_resolve_sheet_name) when the
      configured name didn't match exactly.

    Cells whose header is unmatched (or explicitly mapped to None, e.g.
    the parental-link column) are silently dropped. Empty rows are
    skipped. NO value-side normalisation here — that is
    `_import_normalize_value`'s job inside the import pipeline, so the
    same fold/date/status rules apply for every entry path.
    """
    import io as _io
    from openpyxl import load_workbook
    if _DRIVE_SHEET_MAP.get(table) is None:
        raise RuntimeError("no Drive header map for table " + str(table))
    lookup = _drive_build_header_lookup(table, db)
    try:
        wb = load_workbook(_io.BytesIO(xlsx_bytes), read_only=True, data_only=True)
    except Exception as ex:
        raise RuntimeError("xlsx parse failed: " + str(ex)[:120])
    titles = [ws.title for ws in wb.worksheets]
    try:
        resolved_name, _fallback = _drive_resolve_sheet_name(
            sheet_name, titles, table,
        )
    except RuntimeError:
        try: wb.close()
        except Exception: pass
        raise
    ws = wb[resolved_name]
    rows_iter = ws.iter_rows(values_only=True)
    try:
        header = next(rows_iter)
    except StopIteration:
        try: wb.close()
        except Exception: pass
        return [], [], resolved_name
    col_keys = []
    unmatched = []
    seen_unmatched = set()
    for cell in header:
        raw = "" if cell is None else str(cell)
        if not raw.strip():
            col_keys.append(None)
            continue
        folded = _grp_norm(raw)
        target = lookup.get(folded) if folded else None
        col_keys.append(target)
        if target is None and folded and folded not in seen_unmatched:
            unmatched.append(raw.strip())
            seen_unmatched.add(folded)
    out = []
    for row in rows_iter:
        if row is None:
            continue
        rec = {}
        any_val = False
        for idx, val in enumerate(row):
            if idx >= len(col_keys):
                break
            fk = col_keys[idx]
            if not fk:
                continue
            if val is None:
                rec[fk] = ""
                continue
            sval = str(val)
            if sval.strip():
                any_val = True
            rec[fk] = sval
        if any_val:
            out.append(rec)
    try: wb.close()
    except Exception: pass
    return out, unmatched, resolved_name


IMPORT_TABLE_SQL = {
    "students": "INSERT INTO students",
    "student_groups": "INSERT INTO student_groups",
    "attendance": "INSERT INTO attendance",
    "taqseet": "INSERT INTO taqseet",
    "evaluations": "INSERT INTO evaluations",
    "payment_log": "INSERT INTO payment_log",
}

def _perform_import(table, rows, auto_create, db, column_labels=None):
    """Core import worker shared by /api/import and /api/import/from-drive.

    Takes already-parsed `rows` (list of dicts) and runs the same
    upsert / typed-validation pipeline that /api/import has always
    used. Returns (status_code, payload_dict) so the caller can pass
    straight to jsonify(...).

    Behaviour preserved verbatim from the original api_import body:
      - Every incoming text value is whitespace-folded.
      - Attendance status values are mapped to canonical Arabic
        (غياب→غائب, تأخير→متأخر, حضور→حاضر) so downstream matching works.
      - If all natural-key columns (IMPORT_TABLE_KEYS[table]) are non-empty
        and an existing row has the same key tuple, the row is UPDATED
        (non-key columns only, and only where the incoming value is non-empty
        so we don't overwrite existing data with blanks).
      - Otherwise the row is INSERTED.
      - Typed columns (نص/رقم/تاريخ/نعم-لا) are validated; on failure the
        row is skipped with a reason added to skip_reasons.

    Side effects: ALTER TABLE on auto_create, INSERT INTO taqseet_col_labels
    when relevant, INSERT/UPDATE on the data table. db.commit() called
    at the end.
    """
    column_labels = column_labels or {}
    fields = IMPORT_TABLE_FIELDS.get(table)
    if not fields:
        return 400, {"ok": False, "error": "unknown table"}
    live_cols = {r[1] for r in db.execute("PRAGMA table_info(" + table + ")").fetchall()}

    if auto_create:
        import re as _re_local
        safe_rx = _re_local.compile(r'^[A-Za-z_][A-Za-z0-9_]{0,63}$')
        incoming = set()
        for r in rows:
            if isinstance(r, dict):
                incoming.update(r.keys())
        candidates = set(fields) | {k for k in incoming if safe_rx.match(k or '')}
        missing = candidates - live_cols - {"id"}
        for col in sorted(missing):
            try:
                db.execute("ALTER TABLE " + table + " ADD COLUMN " + col + " TEXT")
                live_cols.add(col)
            except Exception:
                pass
        db.commit()
        fields = [c for c in candidates if c in live_cols]
        if table == 'taqseet' and isinstance(column_labels, dict) and column_labels:
            try:
                for key, label in column_labels.items():
                    if not key or not isinstance(key, str) or not safe_rx.match(key):
                        continue
                    lbl = str(label or '').strip()
                    if not lbl:
                        continue
                    db.execute(
                        "INSERT INTO taqseet_col_labels(col_key,col_label) VALUES(?,?) "
                        "ON CONFLICT(col_key) DO UPDATE SET col_label=EXCLUDED.col_label",
                        (key, lbl),
                    )
                db.commit()
            except Exception:
                pass
    else:
        fields = [f for f in fields if f in live_cols]

    if not fields:
        return 400, {"ok": False, "error": "no matching columns in table " + table}

    # Mirror student_groups days writes into the admin's custom-labelled
    # "أيام الدراسة" column (col_<timestamp>) when one exists, in
    # addition to the legacy `study_days` column. Without this, the
    # admin UI shows the days column empty after import because it
    # reads the custom column first via _row_days_authoritative and
    # only falls back to study_days when the custom column is empty
    # FOR THIS row — but a freshly-imported row always has that
    # custom column NULL until the mirror happens. _groups_days_column
    # returns 'study_days' when no custom column exists, so the
    # equality check below is the no-mirror sentinel.
    custom_days_col = None
    if table == "student_groups" and "study_days" in live_cols:
        try:
            _resolved = _groups_days_column(db)
            if (_resolved and _resolved != "study_days"
                    and _resolved in live_cols
                    and _resolved not in fields
                    and _is_safe_ident(_resolved)):
                custom_days_col = _resolved
                fields = list(fields) + [custom_days_col]
        except Exception:
            custom_days_col = None

    key_cols = [k for k in IMPORT_TABLE_KEYS.get(table, []) if k in live_cols and _is_safe_ident(k)]
    col_types = _import_get_col_types(table)

    inserted = 0
    updated  = 0
    skipped  = 0
    rows_skipped_empty = 0   # subset of `skipped` — placeholder/empty PK rows
    inserted_without_id = 0  # students-only: new rows inserted with NULL personal_id
    errors   = 0
    skip_reasons = []   # up to 20 entries
    last_error = ""
    # Per-column count of rows that arrived with a non-empty value for
    # that field. Surfaced in the response payload so admins can spot
    # "why is column X still empty after import?" without prod DB
    # access — column with `nonempty_writes_per_col[col] == 0` means
    # the sheet either didn't have that header or every row was empty
    # under it. Helps differentiate between (a) header didn't match,
    # (b) header matched but cells were blank, (c) value was rejected
    # downstream.
    nonempty_writes_per_col = {f: 0 for f in fields}

    cols = ",".join(fields)
    placeholders = ",".join(["?"] * len(fields))
    sql_insert = IMPORT_TABLE_SQL[table] + " (" + cols + ") VALUES (" + placeholders + ")"

    def _remember_skip(idx, reason):
        if len(skip_reasons) < 20:
            skip_reasons.append({"row": idx + 1, "reason": reason})

    for idx, r in enumerate(rows):
        if not isinstance(r, dict):
            skipped += 1
            _remember_skip(idx, "row is not an object")
            continue
        norm = {}
        for f in fields:
            norm[f] = _import_normalize_value(table, f, r.get(f))
        # Mirror student_groups days value: incoming row dicts are keyed
        # by English col_keys (study_days), but we ALSO want the value
        # in the admin's custom-labelled col_<timestamp> column so the
        # UI sees it immediately. Sources norm[study_days] directly so
        # the value is the same post-normalisation form that lands in
        # the legacy column.
        if custom_days_col:
            _days_val = norm.get("study_days") or ""
            if _days_val:
                norm[custom_days_col] = _days_val
        # Tally non-empty writes per target column for the diagnostic
        # surface in the response payload.
        for _f in fields:
            if (norm.get(_f) or "").strip():
                nonempty_writes_per_col[_f] = nonempty_writes_per_col.get(_f, 0) + 1
        has_any = any(v for v in norm.values())
        if not has_any:
            skipped += 1
            rows_skipped_empty += 1
            _remember_skip(idx, "empty row")
            continue

        # Reject rows whose primary key is empty/whitespace-only or
        # only contains placeholder punctuation (dashes, dots, bullets).
        # Drive sheets often have summary/separator rows at the bottom
        # like " -  -  -  - " that the has_any check lets through (the
        # dashes are truthy) which then get INSERTed as junk rows with
        # NULL in every other column. Only enforced when the table
        # declares a primary key in IMPORT_TABLE_KEYS.
        #
        # SPECIAL CASE for students: real students often appear in the
        # sheet without a personal_id yet (registration in progress).
        # Their record is still valuable — name, phones, status — so
        # we keep the row when student_name is non-empty. The dedup
        # key for re-imports falls back to student_name in the upsert
        # block below. Only when BOTH personal_id AND student_name
        # are empty/placeholder is the row treated as junk and
        # skipped.
        if key_cols:
            _pk_val = (norm.get(key_cols[0]) or "").strip()
            _pk_invalid = (not _pk_val
                           or bool(_IMPORT_PK_PLACEHOLDER_RX.match(_pk_val)))
            if _pk_invalid:
                if table == "students":
                    _name_val = (norm.get("student_name") or "").strip()
                    _name_invalid = (
                        not _name_val
                        or bool(_IMPORT_PK_PLACEHOLDER_RX.match(_name_val))
                    )
                    if _name_invalid:
                        skipped += 1
                        rows_skipped_empty += 1
                        _remember_skip(
                            idx,
                            "students row missing both personal_id and student_name",
                        )
                        continue
                    # else: name is valid, fall through with NULL ID
                else:
                    skipped += 1
                    rows_skipped_empty += 1
                    _remember_skip(idx, "primary-key is empty/placeholder")
                    continue

        # Typed-column validation.
        bad_type_reason = ""
        for f in fields:
            t = col_types.get(f, "")
            if not t:
                continue
            ok, coerced, why = _import_coerce_by_type(norm[f], t)
            if not ok:
                bad_type_reason = f + ": " + why
                break
            norm[f] = coerced
        if bad_type_reason:
            skipped += 1
            _remember_skip(idx, bad_type_reason)
            continue

        # Upsert: if every key column is non-empty AND a row with that tuple
        # exists, UPDATE non-key columns; else INSERT.
        existing_id = None
        if key_cols and all((norm.get(k) or "").strip() for k in key_cols):
            where = " AND ".join([k + "=?" for k in key_cols])
            try:
                row = db.execute(
                    "SELECT id FROM " + table + " WHERE " + where,
                    tuple(norm[k] for k in key_cols),
                ).fetchone()
                if row:
                    existing_id = row[0] if not hasattr(row, "keys") else row["id"]
            except Exception:
                existing_id = None
        elif table == "students":
            # Students fallback: when personal_id is empty/NULL but
            # student_name is set, look up an existing ID-less row by
            # name so re-imports UPDATE in place rather than creating
            # duplicates. Restricted to rows where personal_id IS NULL
            # — never accidentally pulls in a student that already has
            # a real ID.
            _name_val = (norm.get("student_name") or "").strip()
            if _name_val and "student_name" in live_cols:
                try:
                    _row = db.execute(
                        "SELECT id FROM students "
                        "WHERE personal_id IS NULL AND student_name = ? LIMIT 1",
                        (_name_val,),
                    ).fetchone()
                    if _row:
                        existing_id = _row[0] if not hasattr(_row, "keys") else _row["id"]
                except Exception:
                    existing_id = None

        try:
            if existing_id:
                set_cols = [f for f in fields if f not in key_cols and (norm.get(f) or "").strip()]
                if not set_cols:
                    skipped += 1
                    _remember_skip(idx, "duplicate key with no new data")
                    continue
                sql_up = ("UPDATE " + table + " SET " +
                          ",".join([c + "=?" for c in set_cols]) +
                          " WHERE id=?")
                db.execute(sql_up, tuple([norm[c] for c in set_cols] + [existing_id]))
                updated += 1
            else:
                values = [norm.get(f, "") for f in fields]
                # Empty personal_id -> NULL so UNIQUE(personal_id) treats
                # blank-ID rows as distinct. Only matters for students here.
                _had_null_pk = False
                for i2, f in enumerate(fields):
                    if f == "personal_id" and not (values[i2] or "").strip():
                        values[i2] = None
                        _had_null_pk = True
                cur = db.execute(sql_insert, tuple(values))
                if cur.rowcount > 0:
                    inserted += 1
                    if table == "students" and _had_null_pk:
                        inserted_without_id += 1
                else:
                    skipped += 1
                    _remember_skip(idx, "insert suppressed (UNIQUE?)")
        except Exception as ex:
            errors += 1
            last_error = str(ex)
            _remember_skip(idx, "error: " + last_error[:80])

    db.commit()
    return 200, {
        "ok": True,
        "table": table,
        "inserted": inserted,
        "updated":  updated,
        "skipped":  skipped,
        "rows_skipped_empty": rows_skipped_empty,
        "inserted_without_id": inserted_without_id,
        "errors":   errors,
        "received": len(rows),
        "skip_reasons": skip_reasons,
        "last_error": last_error,
        "fields_used": fields,
        "nonempty_writes_per_col": nonempty_writes_per_col,
        # Backwards-compat aliases (existing front-end reads d.imported/d.ignored).
        "imported": inserted,
        "ignored":  skipped,
    }


@app.route('/api/import', methods=['POST'])
@admin_required
def api_import():
    """Generic Excel-import endpoint used by every table on the database page.

    Thin wrapper around _perform_import — request parsing here, the
    actual upsert / validation pipeline lives in the helper so the new
    /api/import/from-drive endpoint shares the exact same code path.

    Response includes: inserted, updated, skipped, errors, received,
    skip_reasons (up to 20), last_error, fields_used.
    """
    d = request.get_json() or {}
    table = d.get('table', '')
    rows = d.get('rows', [])
    auto_create = bool(d.get('auto_create', False))
    column_labels = d.get('column_labels') or {}
    db = get_db()
    status, payload = _perform_import(
        table, rows, auto_create, db, column_labels=column_labels,
    )
    return jsonify(payload), status


# ─── Drive published-sheets import (Phase C3 + students Phase E) ──────
# Whitelist of tables the /api/import/from-drive endpoint will touch.
# Anything else is rejected with 403. attendance / payment_log /
# student_groups have Drive sheet names seeded by drive_settings_seed_v1
# (C1); students gets its sheet name seeded by drive_settings_students_v1
# (Phase E). The students table is in _TRUNCATE_PROTECTED so it can
# never be wiped through the truncate UI, but it CAN be imported here
# because the import is upsert (no DELETE) on personal_id and is gated
# behind admin role + type-to-confirm.
_DRIVE_IMPORT_ALLOWED = {"attendance", "payment_log", "student_groups", "students"}


@app.route('/api/import/from-drive', methods=['POST'])
@admin_required
def api_import_from_drive():
    """Pull rows from the published Google Sheets workbook and feed them
    through the same _perform_import pipeline as /api/import.

    Steps (in order):
      1. Validate body: table_name + confirm_token (must equal table_name).
      2. Run _pre_destructive_backup BEFORE any read — abort on failure.
      3. Resolve URL + sheet name from settings (integrations.*).
      4. Fetch xlsx via _drive_fetch_xlsx (stdlib only, 60s timeout).
      5. Parse rows via _drive_extract_rows.
      6. Hand to _perform_import (auto_create=False — no schema drift
         from a remote source).
      7. Audit + return JSON with counts and the backup path.
    """
    err = _require_admin_response()
    if err:
        return err
    db = get_db()
    d = request.get_json(silent=True) or {}
    table_name    = (d.get("table_name") or "").strip()
    confirm_token = (d.get("confirm_token") or "").strip()

    if not table_name:
        return jsonify({"ok": False, "error": "اسم الجدول مطلوب"}), 400
    if not _re.match(r"^[A-Za-z0-9_]+$", table_name):
        return jsonify({"ok": False, "error": "اسم الجدول غير صالح"}), 400
    if confirm_token != table_name:
        return jsonify({"ok": False, "error": "التأكيد غير مطابق"}), 400
    if table_name not in _DRIVE_IMPORT_ALLOWED:
        return jsonify({"ok": False,
                        "error": "هذا الجدول غير مدعوم للاستيراد من Drive"}), 403

    # Per-phase timing diagnostics. Surfaced in response payload and
    # stderr so 502 timeouts (or near-timeouts) reveal which phase is
    # slow without prod DB access.
    import time as _t_drv
    _t_drive_start = _t_drv.time()
    _t_backup = 0.0
    _t_fetch  = 0.0
    _t_parse  = 0.0
    _t_import = 0.0

    # Pre-import backup is OPT-IN for Drive imports. The endpoint is
    # upsert-only — IMPORT_TABLE_KEYS dedups on natural keys and
    # _perform_import only UPDATEs columns where the new value is
    # non-empty, so existing data is never overwritten with blanks
    # and no row is ever DELETEd. A backup is therefore not required
    # for data safety. Running it inline often blows past the gunicorn
    # worker timeout (30-60s+ for a full DB dump on Postgres) which
    # was the cause of the HTTP 502 the admin reported. Admin can
    # still trigger a manual backup via /api/backups/run before the
    # import if a snapshot is desired. Pass {"with_backup": true} in
    # the request body to opt back into inline backup. Truncate
    # endpoint /api/admin/table/truncate is unchanged — it still
    # backs up unconditionally because that one IS destructive.
    bk_info = None
    backup_skipped = True
    if d.get("with_backup") is True:
        backup_skipped = False
        _t_b0 = _t_drv.time()
        try:
            bk_info = _pre_destructive_backup("import-from-drive:" + table_name)
        except Exception as ex:
            import sys as _sys, traceback as _tb
            _sys.stderr.write("[drive-import] backup failed: " + str(ex) + "\n")
            _sys.stderr.write(_tb.format_exc() + "\n")
            return jsonify({
                "ok": False,
                "error": "تعذر إنشاء نسخة احتياطية. لا يمكن المتابعة بدون نسخة محفوظة.",
                "exc_type": type(ex).__name__,
                "stage": "backup",
            }), 500
        _t_backup = _t_drv.time() - _t_b0

    # Resolve URL + sheet name from settings (seeded in C1).
    url = (get_setting("integrations", "drive_workbook_url", "") or "").strip()
    if not url:
        return jsonify({"ok": False,
                        "error": "رابط Drive غير معرّف في الإعدادات"}), 400
    sheet_setting_key = "drive_sheet_" + table_name
    sheet_name = (get_setting("integrations", sheet_setting_key, "") or "").strip()
    if not sheet_name:
        return jsonify({"ok": False,
                        "error": "اسم ورقة Drive غير معرّف في الإعدادات"}), 400

    # Fetch xlsx bytes.
    _t_f0 = _t_drv.time()
    try:
        xlsx_bytes = _drive_fetch_xlsx(url)
    except Exception as ex:
        import sys as _sys, traceback as _tb
        _sys.stderr.write("[drive-import] fetch failed: " + str(ex) + "\n")
        _sys.stderr.write(_tb.format_exc() + "\n")
        return jsonify({
            "ok": False,
            "error": "تعذر جلب الملف من Drive: " + str(ex)[:200],
            "exc_type": type(ex).__name__,
            "stage": "fetch_xlsx",
        }), 502
    _t_fetch = _t_drv.time() - _t_f0

    # Parse the requested sheet (live-label-aware lookup via db). The
    # resolver is fuzzy: configured-name-exact → folded-equality →
    # _DRIVE_SHEET_VARIANTS list → folded substring (only when exactly
    # one title qualifies). resolved_sheet_name is the actual worksheet
    # title that was opened, surfaced to the response so the admin can
    # see when the configured name didn't match exactly.
    resolved_sheet_name = sheet_name
    _t_p0 = _t_drv.time()
    try:
        rows, unmatched_headers, resolved_sheet_name = _drive_extract_rows(
            table_name, xlsx_bytes, sheet_name, db=db,
        )
    except Exception as ex:
        import sys as _sys, traceback as _tb
        _sys.stderr.write("[drive-import] extract failed: " + str(ex) + "\n")
        _sys.stderr.write(_tb.format_exc() + "\n")
        msg = str(ex)
        # Sheet-missing maps to 404; everything else (xlsx parse, header
        # map missing) maps to 502 since the upstream payload is bad.
        if msg.startswith("sheet not found"):
            return jsonify({
                "ok": False,
                "error": "الورقة غير موجودة في ملف Drive: " + msg[:200],
                "exc_type": type(ex).__name__,
                "stage": "extract_rows",
            }), 404
        return jsonify({
            "ok": False,
            "error": "فشل قراءة الملف: " + msg[:200],
            "exc_type": type(ex).__name__,
            "stage": "extract_rows",
        }), 502
    _t_parse = _t_drv.time() - _t_p0

    # Run through the shared import pipeline (same code path as /api/import).
    _t_i0 = _t_drv.time()
    try:
        status, payload = _perform_import(
            table_name, rows, auto_create=False, db=db, column_labels=None,
        )
    except Exception as ex:
        import sys as _sys, traceback as _tb
        _sys.stderr.write("[drive-import] perform_import failed: " + str(ex) + "\n")
        _sys.stderr.write(_tb.format_exc() + "\n")
        return jsonify({
            "ok": False,
            "error": "فشل أثناء الاستيراد: " + str(ex)[:200],
            "exc_type": type(ex).__name__,
            "stage": "perform_import",
        }), 500
    _t_import = _t_drv.time() - _t_i0

    # Audit log entry — best-effort, never blocks the response.
    try:
        u = session.get("user") or {}
        _audit(
            "import.from_drive",
            target_type="table", target_id=table_name,
            new_value={
                "inserted": payload.get("inserted", 0),
                "updated":  payload.get("updated", 0),
                "skipped":  payload.get("skipped", 0),
                "errors":   payload.get("errors", 0),
            },
            details={
                "source_sheet": sheet_name,
                "resolved_sheet_name": resolved_sheet_name,
                "fallback_used": (resolved_sheet_name != sheet_name),
                "source_url":   url,
                "received":     payload.get("received", 0),
                "unmatched_headers": unmatched_headers,
                "backup_filename": (bk_info.get("filename")
                                    if isinstance(bk_info, dict) else None),
                "backup_path":     (bk_info.get("path")
                                    if isinstance(bk_info, dict) else None),
                "actor": u.get("username") or "",
            },
        )
    except Exception:
        pass

    # Per-phase timing summary to stderr (visible in Render Logs) so
    # 502 timeouts or near-timeouts are immediately diagnosable.
    _t_total = _t_drv.time() - _t_drive_start
    try:
        import sys as _sys_t
        _sys_t.stderr.write(
            "[drive-import] table=" + table_name
            + " resolved_sheet=" + repr(resolved_sheet_name)
            + " rows=" + str(len(rows))
            + " backup=" + ("%.1fs" % _t_backup)
            + " fetch="  + ("%.1fs" % _t_fetch)
            + " parse="  + ("%.1fs" % _t_parse)
            + " import=" + ("%.1fs" % _t_import)
            + " total="  + ("%.1fs" % _t_total)
            + " inserted=" + str(payload.get("inserted", 0))
            + " updated="  + str(payload.get("updated", 0))
            + " skipped="  + str(payload.get("skipped", 0))
            + "\n"
        )
    except Exception:
        pass

    # Augment payload with Drive-specific fields the UI shows alongside counts.
    payload["source_sheet"]      = sheet_name
    payload["source_url"]        = url
    payload["unmatched_headers"] = unmatched_headers
    payload["resolved_sheet_name"]   = resolved_sheet_name
    payload["configured_sheet_name"] = sheet_name
    payload["fallback_used"]         = (resolved_sheet_name != sheet_name)
    payload["backup_skipped"]    = backup_skipped
    payload["backup_path"]       = ((bk_info.get("path")
                                     if isinstance(bk_info, dict) else "") or "")
    payload["timings_ms"] = {
        "backup": int(_t_backup * 1000),
        "fetch":  int(_t_fetch * 1000),
        "parse":  int(_t_parse * 1000),
        "import": int(_t_import * 1000),
        "total":  int(_t_total * 1000),
    }
    return jsonify(payload), status

@app.route('/api/attendance/sessions', methods=['GET'])
@login_required
def api_attendance_sessions():
    db = get_db()
    rows = db.execute(
        "SELECT a.group_name, COUNT(DISTINCT a.attendance_date) AS sessions, "
        "COALESCE((SELECT SUM(duration_minutes) FROM session_durations sd "
        "          WHERE sd.group_name = a.group_name), 0) AS total_minutes "
        "FROM attendance a "
        "WHERE a.group_name IS NOT NULL AND a.group_name != '' "
        "AND a.attendance_date IS NOT NULL AND a.attendance_date != '' "
        "GROUP BY a.group_name ORDER BY a.group_name"
    ).fetchall()
    return jsonify([
        {"group_name": r[0], "sessions": r[1], "total_minutes": int(r[2] or 0)}
        for r in rows
    ])

@app.route('/api/attendance/groups', methods=['GET'])
@login_required
def api_attendance_groups():
    # Configurable via /settings → attendance.groups_table / groups_column.
    tbl = get_setting('attendance', 'groups_table', 'attendance')
    col = get_setting('attendance', 'groups_column', 'group_name')
    if not _is_safe_ident(tbl) or not _is_safe_ident(col):
        tbl, col = 'attendance', 'group_name'
    db = get_db()
    rows = db.execute(
        "SELECT DISTINCT " + col + " FROM " + tbl + " "
        "WHERE " + col + " IS NOT NULL AND " + col + " != '' "
        "ORDER BY " + col
    ).fetchall()
    return jsonify([r[0] for r in rows])

@app.route('/api/attendance/group-dates', methods=['GET'])
@login_required
def api_attendance_group_dates():
    group = request.args.get('group', '')
    db = get_db()
    rows = db.execute(
        "SELECT DISTINCT a.attendance_date, "
        "COALESCE(sd.duration_minutes, 0) AS duration, "
        "COALESCE(sd.session_type, '') AS session_type "
        "FROM attendance a "
        "LEFT JOIN session_durations sd "
        "  ON sd.group_name = a.group_name AND sd.session_date = a.attendance_date "
        "WHERE a.group_name = ? AND a.attendance_date IS NOT NULL AND a.attendance_date != '' "
        "ORDER BY a.attendance_date",
        (group,)
    ).fetchall()
    return jsonify([
        {"session_date": r[0], "duration_minutes": int(r[1] or 0), "session_type": r[2] or ""}
        for r in rows
    ])

@app.route('/api/session-durations', methods=['POST'])
@login_required
def api_session_durations_save():
    d = request.get_json() or {}
    group = d.get('group_name', '')
    items = d.get('items', [])
    if not group:
        return jsonify({"ok": False, "error": "group_name required"}), 400
    db = get_db()
    try:
        for it in items:
            date = it.get('session_date', '')
            mins = int(it.get('duration_minutes') or 0)
            stype = (it.get('session_type') or '').strip()
            if not date:
                continue
            db.execute(
                "INSERT INTO session_durations(group_name, session_date, duration_minutes, session_type) "
                "VALUES(?,?,?,?) "
                "ON CONFLICT(group_name, session_date) DO UPDATE SET "
                "  duration_minutes=excluded.duration_minutes, "
                "  session_type=excluded.session_type",
                (group, date, mins, stype)
            )
        db.commit()
        return jsonify({"ok": True})
    except Exception as ex:
        return jsonify({"ok": False, "error": str(ex)}), 400

@app.route('/api/session-summary', methods=['GET'])
@login_required
def api_session_summary():
    db = get_db()
    HUDOOR = '\u062D\u0636\u0648\u0631'
    ONLINE = '\u0623\u0648\u0646\u0644\u0627\u064A\u0646'

    groups = db.execute(
        "SELECT group_name, COALESCE(total_required_hours,'') "
        "FROM student_groups "
        "WHERE group_name IS NOT NULL AND group_name != '' "
        "ORDER BY group_name"
    ).fetchall()

    known = set()
    result = []
    for g in groups:
        name = g[0]
        try:
            req_hours = float(str(g[1]).strip()) if str(g[1]).strip() else 0.0
        except Exception:
            req_hours = 0.0
        totals = db.execute(
            "SELECT COALESCE(session_type,'') AS st, COALESCE(SUM(duration_minutes),0) "
            "FROM session_durations WHERE group_name=? GROUP BY st",
            (name,)
        ).fetchall()
        pres_m = 0
        onl_m = 0
        other_m = 0
        for t in totals:
            st = (t[0] or '').strip()
            mins = int(t[1] or 0)
            if st == HUDOOR:
                pres_m += mins
            elif st == ONLINE:
                onl_m += mins
            else:
                other_m += mins
        total_m = pres_m + onl_m + other_m
        total_h = round(total_m / 60.0, 2)
        pres_h = round(pres_m / 60.0, 2)
        onl_h = round(onl_m / 60.0, 2)
        remaining_h = round(req_hours - total_h, 2)
        if req_hours > 0:
            pct = max(0.0, min(100.0, round((total_h / req_hours) * 100.0, 1)))
        else:
            pct = 0.0
        result.append({
            "group_name": name,
            "required_hours": req_hours,
            "present_hours": pres_h,
            "online_hours": onl_h,
            "total_hours": total_h,
            "remaining_hours": remaining_h,
            "completion_pct": pct,
        })
        known.add(name)

    extra = db.execute(
        "SELECT DISTINCT group_name FROM session_durations "
        "WHERE group_name IS NOT NULL AND group_name != ''"
    ).fetchall()
    for e in extra:
        name = e[0]
        if name in known:
            continue
        totals = db.execute(
            "SELECT COALESCE(session_type,'') AS st, COALESCE(SUM(duration_minutes),0) "
            "FROM session_durations WHERE group_name=? GROUP BY st",
            (name,)
        ).fetchall()
        pres_m = 0
        onl_m = 0
        other_m = 0
        for t in totals:
            st = (t[0] or '').strip()
            mins = int(t[1] or 0)
            if st == HUDOOR:
                pres_m += mins
            elif st == ONLINE:
                onl_m += mins
            else:
                other_m += mins
        total_m = pres_m + onl_m + other_m
        result.append({
            "group_name": name,
            "required_hours": 0.0,
            "present_hours": round(pres_m / 60.0, 2),
            "online_hours": round(onl_m / 60.0, 2),
            "total_hours": round(total_m / 60.0, 2),
            "remaining_hours": round(-total_m / 60.0, 2),
            "completion_pct": 0.0,
        })

    result.sort(key=lambda r: r["group_name"] or "")
    return jsonify(result)

@app.route('/api/payments/group')
@login_required
def api_payments_group():
    """Students in the chosen group + their per-installment plan and
    payment status. Two long-standing bugs are addressed here:

    1. Online-only groups returned empty because the WHERE clause only
       checked `group_name_student`. Now we accept either the in-person
       column OR the online column (both configurable via settings),
       trimming both sides so a stray space won\'t miss a match.
    2. The taqseet lookup used `taqseet_method`, an ASCII column that
       was DROPPED in the v4 rebuild — every call raised
       UndefinedColumn and 500\'d. We now read from the live taqseet
       row whose `id` OR `طريقة_التقسيط` matches the student\'s stored
       installment_type, pulling the v4-named installment columns
       (`القسط_1`..`القسط_12`).
    """
    db = get_db()
    group = (request.args.get('group') or '').strip()
    if not group:
        return jsonify([])

    # Resolve column names from settings, with hardcoded fallbacks.
    in_col     = get_setting('attendance', 'student_group_column',         'group_name_student')
    online_col = get_setting('attendance', 'student_online_group_column',  'group_online')
    if not _is_safe_ident(in_col):     in_col = 'group_name_student'
    if not _is_safe_ident(online_col): online_col = 'group_online'

    # Confirm columns exist on the live schema; fall back gracefully.
    try:
        live_cols = {r[1] for r in db.execute("PRAGMA table_info(students)").fetchall()}
    except Exception:
        live_cols = set()
    has_online = online_col in live_cols and online_col != in_col

    if has_online:
        sql = (
            'SELECT id, student_name, installment_type FROM students '
            'WHERE TRIM(COALESCE("' + in_col + '", \'\')) = ? '
            'OR TRIM(COALESCE("' + online_col + '", \'\')) = ? '
            'ORDER BY student_name'
        )
        students = db.execute(sql, (group, group)).fetchall()
    else:
        sql = (
            'SELECT id, student_name, installment_type FROM students '
            'WHERE TRIM(COALESCE("' + in_col + '", \'\')) = ? '
            'ORDER BY student_name'
        )
        students = db.execute(sql, (group,)).fetchall()

    # Pre-load taqseet rows once (cheap — the table is tiny).
    tq_rows = []
    try:
        tq_cols = [r[1] for r in db.execute("PRAGMA table_info(taqseet)").fetchall()]
        # Build a SELECT that survives both the v4 schema (Arabic
        # columns) and any legacy DB that still has `taqseet_method`.
        def _q(c): return '"' + c + '"' if c in tq_cols else 'NULL AS ' + c
        method_alias = '"طريقة_التقسيط"' if 'طريقة_التقسيط' in tq_cols else ('taqseet_method' if 'taqseet_method' in tq_cols else "''")
        inst_select = []
        for n in range(1, 13):
            v4 = 'القسط_' + str(n)
            legacy = 'inst' + str(n)
            if v4 in tq_cols:
                inst_select.append('"' + v4 + '" AS i' + str(n))
            elif legacy in tq_cols:
                inst_select.append(legacy + ' AS i' + str(n))
            else:
                inst_select.append("'' AS i" + str(n))
        sql_tq = ('SELECT id, ' + method_alias + ' AS m, '
                  + ', '.join(inst_select) + ' FROM taqseet')
        tq_rows = db.execute(sql_tq).fetchall()
    except Exception:
        tq_rows = []

    def _find_taqseet(stored):
        if stored is None: return None
        s = str(stored).strip()
        if not s: return None
        for r in tq_rows:
            tid    = r[0]
            method = r[1]
            if str(tid) == s or (method is not None and str(method) == s):
                return r
        return None

    result = []
    for s in students:
        sid, sname, itype = s[0], s[1], s[2]
        row = {"id": sid, "name": sname}
        tq = _find_taqseet(itype)
        if tq:
            for n in range(1, 13):
                v = tq[1 + n]  # row layout: id, m, i1..i12
                row["tq_inst" + str(n)] = ('' if v is None else v)
        try:
            payments = db.execute(
                "SELECT inst_num,inst_type,price,paid FROM student_payments WHERE student_id=?",
                (sid,),
            ).fetchall()
        except Exception:
            payments = []
        for p in payments:
            row["inst_" + str(p[0])] = {"inst_type": p[1], "price": p[2], "paid": p[3]}
        result.append(row)
    return jsonify(result)


# ─── New payment-followup workflow ──────────────────────────────────
# Three endpoints power the redesigned متابعة الدفع modal:
#   GET  /api/payment/student/<sid>/plan
#        → installment plan + per-installment paid/remaining + totals
#   GET  /api/payment/student/<sid>/installment/<n>
#        → details for a single installment
#   POST /api/payment/student/<sid>/pay   body {n, amount}
#        → record an additional payment, validate against remaining
#
# All read taqseet through the v4 Arabic columns with legacy fallback.
# Per-installment paid amounts live in student_payments (student_id,
# inst_num) — same table the legacy /api/payments/<sid>/<n> route uses,
# so both code paths stay in sync.
def _payment_load_taqseet_rows(db):
    """Return [(id, method, inst1..12, date1..12)] schema-normalised."""
    try:
        cols = {r[1] for r in db.execute("PRAGMA table_info(taqseet)").fetchall()}
    except Exception:
        cols = set()
    method_expr = ('"طريقة_التقسيط"' if 'طريقة_التقسيط' in cols
                   else ('taqseet_method' if 'taqseet_method' in cols else "''"))
    inst_exprs, date_exprs = [], []
    for n in range(1, 13):
        v4i, lgi = 'القسط_' + str(n), 'inst' + str(n)
        v4d, lgd = 'تاريخ_الاستحقاق_' + str(n), 'date' + str(n)
        inst_exprs.append('"' + v4i + '"' if v4i in cols else (lgi if lgi in cols else "''") + ' AS i' + str(n))
        date_exprs.append('"' + v4d + '"' if v4d in cols else (lgd if lgd in cols else "''") + ' AS d' + str(n))
    select = ('SELECT id, ' + method_expr + ' AS m, '
              + ', '.join('(' + e + ') AS i' + str(n + 1) for n, e in enumerate(inst_exprs))
              + ', ' + ', '.join('(' + e + ') AS d' + str(n + 1) for n, e in enumerate(date_exprs))
              + ' FROM taqseet')
    try:
        return db.execute(select).fetchall()
    except Exception:
        return []

def _payment_find_taqseet(rows, stored):
    if stored is None: return None
    s = str(stored).strip()
    if not s: return None
    for r in rows:
        if str(r[0]) == s or (r[1] is not None and str(r[1]) == s):
            return r
    return None

def _payment_to_float(v):
    if v is None: return 0.0
    s = str(v).strip().replace(',', '')
    if not s: return 0.0
    try: return float(s)
    except Exception: return 0.0

def _payment_load_student(db, sid):
    in_col     = get_setting('attendance', 'student_group_column',         'group_name_student')
    online_col = get_setting('attendance', 'student_online_group_column',  'group_online')
    if not _is_safe_ident(in_col):     in_col = 'group_name_student'
    if not _is_safe_ident(online_col): online_col = 'group_online'
    try:
        live_cols = {r[1] for r in db.execute("PRAGMA table_info(students)").fetchall()}
    except Exception:
        live_cols = set()
    has_online = online_col in live_cols and online_col != in_col
    cols = ['id', 'student_name', 'personal_id', 'installment_type', in_col]
    if has_online: cols.append(online_col)
    select = 'SELECT ' + ', '.join('"' + c + '"' for c in cols) + ' FROM students WHERE id=?'
    row = db.execute(select, (sid,)).fetchone()
    if not row:
        return None
    d = {
        'id':              row[0],
        'name':            row[1],
        'personal_id':     row[2],
        'installment_type': row[3],
        'group':           row[4] or (row[5] if has_online and len(row) > 5 else ''),
        'group_online':    (row[5] if has_online and len(row) > 5 else ''),
    }
    return d

def _payment_normalize_name(s):
    """Whitespace-collapse and strip diacritics so a payment_log row
    survives slight name spelling differences (extra space, alef
    variants, ta-marbuta vs heh, etc.) when matched against the
    students.student_name."""
    if not s: return ''
    s = str(s)
    repl = {
        'أ': 'ا', 'إ': 'ا', 'آ': 'ا', 'ٱ': 'ا',
        'ة': 'ه', 'ى': 'ي',
    }
    for k, v in repl.items():
        s = s.replace(k, v)
    # Strip Arabic tashkeel marks.
    import re as _re
    s = _re.sub(r'[ً-ٟ]', '', s)
    s = ' '.join(s.split())
    return s.strip().lower()

def _payment_log_paid_for_student(db, student_name, personal_id):
    """Return (paid_by_inst, pl_row_dict) read DIRECTLY from
    payment_log. pl_row_dict carries the persisted total_paid,
    total_remaining, course_amount, and msg1..msg5 columns when they
    exist on the live schema (they were added in the paylog v2
    migration). Lookup ladder: personal_id → exact-normalised
    student_name → ILIKE substring."""
    paid_by_inst = {}
    pl_row = None
    # Detect which paylog columns exist (course_amount, total_paid,
    # total_remaining, msg1..msg5 were added later — be tolerant of
    # legacy DBs without them).
    try:
        live_cols = {r[1] for r in db.execute("PRAGMA table_info(payment_log)").fetchall()}
    except Exception:
        live_cols = set()
    extra_cols = []
    for c in ('course_amount', 'total_paid', 'total_remaining',
              'msg1', 'msg2', 'msg3', 'msg4', 'msg5'):
        if c in live_cols:
            extra_cols.append(c)
    select_cols = (
        ['student_name', 'inst1', 'inst2', 'inst3', 'inst4', 'inst5']
        + extra_cols
    )
    select_sql_base = ('SELECT ' + ', '.join('"' + c + '"' for c in select_cols)
                       + ' FROM payment_log ')
    try:
        if personal_id and str(personal_id).strip():
            pl_row = db.execute(
                select_sql_base + "WHERE personal_id=? AND personal_id <> '' LIMIT 1",
                (str(personal_id).strip(),),
            ).fetchone()
        if not pl_row and student_name:
            target = _payment_normalize_name(student_name)
            for r in db.execute(select_sql_base).fetchall():
                if _payment_normalize_name(r[0]) == target:
                    pl_row = r; break
            if not pl_row:
                row = db.execute(
                    select_sql_base + "WHERE student_name ILIKE ? LIMIT 1",
                    ('%' + str(student_name).strip() + '%',),
                ).fetchone()
                if row: pl_row = row
    except Exception:
        pl_row = None
    if not pl_row:
        return paid_by_inst, None
    for n in range(1, 6):
        v = pl_row[n]
        if v is None: continue
        s = str(v).strip()
        if not s: continue
        if 'تم الدفع' in s:
            paid_by_inst[n] = ('__paid__', s)
        elif 'معفي' in s or 'معفى' in s:
            paid_by_inst[n] = ('__exempt__', s)
        else:
            paid_by_inst[n] = _payment_to_float(s)
    # Build a dict-style view of the row including the extra cols.
    extras = {c: pl_row[6 + i] for i, c in enumerate(extra_cols)}
    pl_dict = {
        'student_name': pl_row[0],
        'inst1': pl_row[1], 'inst2': pl_row[2], 'inst3': pl_row[3],
        'inst4': pl_row[4], 'inst5': pl_row[5],
        **extras,
    }
    return paid_by_inst, pl_dict

def _payment_compute_plan(db, sid):
    """Build the plan payload for a given student. Returns None if the
    student doesn\'t exist.

    Source-of-truth for *paid* amounts is `payment_log` (per spec).
    student_payments stays as a fallback for installments 6..12 (the
    legacy paylog only has 5 inst columns), and for any student whose
    name doesn't resolve in payment_log."""
    student = _payment_load_student(db, sid)
    if not student:
        return None
    tq_rows = _payment_load_taqseet_rows(db)
    tq      = _payment_find_taqseet(tq_rows, student.get('installment_type'))

    paid_pl, pl_row = _payment_log_paid_for_student(
        db, student.get('name'), student.get('personal_id')
    )
    # Backfill from student_payments for any installment payment_log
    # doesn't cover (typically n in 6..12 since paylog only has 5 cols).
    paid_sp = {}
    try:
        for r in db.execute(
            "SELECT inst_num, paid FROM student_payments WHERE student_id=?",
            (sid,),
        ).fetchall():
            try: paid_sp[int(r[0])] = _payment_to_float(r[1])
            except Exception: pass
    except Exception:
        pass

    # Last reminder sent per installment for this student. Newest row wins.
    last_msg = {}
    try:
        for r in db.execute(
            "SELECT installment_number, sent_at, sent_by FROM payment_messages "
            "WHERE student_id=? AND installment_number IS NOT NULL "
            "ORDER BY sent_at DESC",
            (sid,),
        ).fetchall():
            try:
                k = int(r[0])
            except Exception:
                continue
            if k not in last_msg:
                last_msg[k] = (str(r[1] or ''), str(r[2] or ''))
    except Exception:
        pass

    installments = []
    course_amount = 0.0
    has_exempt = False
    if tq:
        for n in range(1, 13):
            amt = _payment_to_float(tq[1 + n])     # row layout: id, m, i1..i12, d1..d12
            if amt <= 0:
                continue
            due = tq[1 + 12 + n]
            pl_val = paid_pl.get(n)
            inst_status = ''
            paid_token  = ''
            if isinstance(pl_val, tuple):
                kind, raw = pl_val
                paid_token = raw
                if kind == '__paid__':
                    paid = amt
                    inst_status = 'paid_token'
                elif kind == '__exempt__':
                    paid = amt
                    inst_status = 'exempt'
                    has_exempt = True
                else:
                    paid = 0.0
            elif isinstance(pl_val, (int, float)):
                paid = float(pl_val)
            else:
                paid = paid_sp.get(n, 0.0)
            _msg = last_msg.get(n) or ('', '')
            installments.append({
                "n":         n,
                "amount":    amt,
                "due_date":  ('' if due is None else str(due)),
                "paid":      paid,
                "remaining": max(0.0, amt - paid),
                "status":    inst_status,
                "token":     paid_token,
                "source":    'payment_log' if pl_val is not None else 'student_payments',
                "last_msg_sent_at": _msg[0],
                "last_msg_sent_by": _msg[1],
            })
            course_amount += amt
    # Per spec: prefer the persisted columns on payment_log when they
    # carry actual data — never zero-out a student whose paylog row
    # already records a paid total.
    total_paid_calc = sum(i["paid"] for i in installments)
    total_paid_pl = None
    course_amount_pl = None
    total_remaining_pl = None
    if pl_row:
        v = pl_row.get('total_paid')
        if v is not None and v != '':
            try: total_paid_pl = float(v)
            except Exception: total_paid_pl = None
        v = pl_row.get('course_amount')
        if v is not None and v != '':
            try: course_amount_pl = float(v)
            except Exception: course_amount_pl = None
        v = pl_row.get('total_remaining')
        if v is not None and v != '':
            try: total_remaining_pl = float(v)
            except Exception: total_remaining_pl = None
    total_paid = total_paid_pl if total_paid_pl is not None else total_paid_calc
    if course_amount_pl is not None and course_amount_pl > 0:
        course_amount = course_amount_pl
    if total_remaining_pl is not None:
        total_remaining = total_remaining_pl
    else:
        total_remaining = max(0.0, course_amount - total_paid)
    method_label = ''
    if tq:
        method_label = '' if tq[1] is None else str(tq[1])
    if course_amount <= 0:
        status = 'unknown'
    elif has_exempt and total_remaining <= 0.005:
        status = 'exempt'
    elif total_remaining <= 0.005:
        status = 'paid'
    elif total_paid <= 0.005:
        status = 'unpaid'
    else:
        status = 'partial'
    return {
        "student": {
            "id":           student['id'],
            "name":         student['name'],
            "personal_id":  student.get('personal_id') or '',
            "group":        student.get('group') or '',
            "group_online": student.get('group_online') or '',
        },
        "plan": {
            "method":          method_label,
            "method_id":       (tq[0] if tq else None),
            "course_amount":   course_amount,
            "num_installments": len(installments),
            "installments":    installments,
            "total_paid":      total_paid,
            "total_remaining": total_remaining,
            "status":          status,
            "paylog_matched":  bool(pl_row),
            "totals_source":   "payment_log" if total_paid_pl is not None else "computed",
        },
    }

@app.route('/api/payment/student/<int:sid>/plan', methods=['GET'])
@login_required
def api_payment_student_plan(sid):
    db = get_db()
    plan = _payment_compute_plan(db, sid)
    if plan is None:
        return jsonify({"ok": False, "error": "student not found"}), 404
    plan["ok"] = True
    return jsonify(plan)

@app.route('/api/payment/student/<int:sid>/installment/<int:n>', methods=['GET'])
@login_required
def api_payment_student_installment(sid, n):
    db = get_db()
    plan = _payment_compute_plan(db, sid)
    if plan is None:
        return jsonify({"ok": False, "error": "student not found"}), 404
    for inst in plan["plan"]["installments"]:
        if inst["n"] == n:
            return jsonify({
                "ok":        True,
                "n":         n,
                "amount":    inst["amount"],
                "due_date":  inst["due_date"],
                "paid":      inst["paid"],
                "remaining": inst["remaining"],
                "student":   plan["student"],
            })
    return jsonify({"ok": False, "error": "installment not in this student\'s plan"}), 404

@app.route('/api/payment/student/<int:sid>/pay', methods=['POST'])
@login_required
def api_payment_student_pay(sid):
    d = request.get_json() or {}
    try:
        n = int(d.get('n') or 0)
    except Exception:
        n = 0
    amount = _payment_to_float(d.get('amount'))
    if n < 1 or n > 12:
        return jsonify({"ok": False, "error": "invalid installment number"}), 400
    if amount <= 0:
        return jsonify({"ok": False, "error": "amount must be > 0"}), 400
    db = get_db()
    plan = _payment_compute_plan(db, sid)
    if plan is None:
        return jsonify({"ok": False, "error": "student not found"}), 404
    target = None
    for inst in plan["plan"]["installments"]:
        if inst["n"] == n:
            target = inst; break
    if target is None:
        return jsonify({"ok": False, "error": "installment not in this student\'s plan"}), 400
    if amount > target["remaining"] + 0.005:
        return jsonify({
            "ok": False,
            "error": "المبلغ المدخل يتجاوز المتبقي من هذا القسط",
            "remaining": target["remaining"],
        }), 400
    new_paid = target["paid"] + amount
    student = plan["student"]
    pid     = (student.get('personal_id') or '').strip()
    sname   = (student.get('name') or '').strip()
    course_amount_now = plan["plan"]["course_amount"]

    # PRIMARY write: payment_log.inst<N>, msg<N>, total_paid,
    # total_remaining, course_amount. The spec wants the totals
    # persisted so the next read can trust them directly. Match an
    # existing row by personal_id → exact name → ILIKE substring;
    # INSERT a new row only if no match.
    if n <= 5:
        try:
            paid_str = ('%g' % new_paid) if new_paid == int(new_paid) else str(new_paid)
            inst_col = 'inst' + str(n)
            msg_col  = 'msg'  + str(n)
            try:
                live_cols = {r[1] for r in db.execute(
                    "PRAGMA table_info(payment_log)"
                ).fetchall()}
            except Exception:
                live_cols = set()
            has_msg   = msg_col in live_cols
            has_total = 'total_paid' in live_cols and 'total_remaining' in live_cols
            has_amount= 'course_amount' in live_cols
            # Resolve the row id once via the same lookup ladder.
            row_id = None
            if pid:
                r = db.execute(
                    "SELECT id FROM payment_log "
                    "WHERE personal_id=? AND personal_id <> '' LIMIT 1",
                    (pid,),
                ).fetchone()
                if r: row_id = r[0]
            if row_id is None and sname:
                r = db.execute(
                    "SELECT id FROM payment_log WHERE TRIM(student_name)=? LIMIT 1",
                    (sname,),
                ).fetchone()
                if r: row_id = r[0]
            if row_id is None and sname:
                r = db.execute(
                    "SELECT id FROM payment_log WHERE student_name ILIKE ? LIMIT 1",
                    ('%' + sname + '%',),
                ).fetchone()
                if r: row_id = r[0]
            if row_id is None:
                # INSERT a fresh row.
                cols  = ['student_name', inst_col]
                vals  = [sname, paid_str]
                if pid: cols.insert(0, 'personal_id'); vals.insert(0, pid)
                if has_msg:    cols.append(msg_col);          vals.append('تم الدفع')
                if has_amount and course_amount_now: cols.append('course_amount'); vals.append(course_amount_now)
                if has_total:  cols += ['total_paid', 'total_remaining']; vals += [new_paid, max(0.0, (course_amount_now or 0) - new_paid)]
                ph = ','.join(['?'] * len(vals))
                db.execute(
                    'INSERT INTO payment_log(' + ','.join('"' + c + '"' for c in cols) + ') VALUES(' + ph + ')',
                    tuple(vals),
                )
                row_id = db.execute("SELECT MAX(id) FROM payment_log").fetchone()[0]
            else:
                # UPDATE the existing row's inst<N> + msg<N> + totals.
                set_pairs = ['"' + inst_col + '"=?']
                params    = [paid_str]
                if has_msg:
                    set_pairs.append('"' + msg_col + '"=?');     params.append('تم الدفع')
                if has_amount and course_amount_now:
                    set_pairs.append('"course_amount"=?');       params.append(course_amount_now)
                params.append(row_id)
                db.execute(
                    'UPDATE payment_log SET ' + ', '.join(set_pairs) + ' WHERE id=?',
                    tuple(params),
                )
            # Recompute persisted totals from the live inst columns +
            # the just-applied write. Token cells ("تم الدفع" / "معفي")
            # contribute by their installment\'s plan amount, since
            # they\'re full-paid markers.
            if has_total:
                fresh = db.execute(
                    'SELECT inst1,inst2,inst3,inst4,inst5 FROM payment_log WHERE id=?',
                    (row_id,),
                ).fetchone()
                fresh_total = 0.0
                for k in range(1, 6):
                    cell = fresh[k - 1]
                    if cell is None: continue
                    s = str(cell).strip()
                    if not s: continue
                    if 'تم الدفع' in s or 'معفي' in s or 'معفى' in s:
                        # Look up the matching plan amount; default to
                        # what we know about target if k == n.
                        plan_amt = 0.0
                        if k == n:
                            plan_amt = target["amount"]
                        else:
                            for inst in plan["plan"]["installments"]:
                                if inst["n"] == k: plan_amt = inst["amount"]; break
                        fresh_total += plan_amt
                    else:
                        fresh_total += _payment_to_float(s)
                fresh_remaining = max(0.0, (course_amount_now or 0) - fresh_total)
                db.execute(
                    'UPDATE payment_log SET total_paid=?, total_remaining=? WHERE id=?',
                    (fresh_total, fresh_remaining, row_id),
                )
            db.commit()
        except Exception as ex:
            return jsonify({"ok": False, "error": "payment_log write failed: " + str(ex)}), 500

    # Secondary mirror: student_payments (handles n in 6..12 cleanly,
    # since payment_log only has 5 inst columns; also keeps the legacy
    # /api/payments/<sid>/<n> endpoint consistent).
    try:
        db.execute(
            """INSERT INTO student_payments(student_id, inst_num, inst_type, price, paid)
               VALUES(?,?,?,?,?)
               ON CONFLICT(student_id, inst_num)
                 DO UPDATE SET paid=EXCLUDED.paid, price=EXCLUDED.price""",
            (sid, n, str(n), target["amount"], new_paid),
        )
        db.commit()
    except Exception:
        pass

    new_plan = _payment_compute_plan(db, sid)
    new_plan["ok"] = True
    new_plan["recorded"] = {"n": n, "amount": amount, "new_paid": new_paid}
    return jsonify(new_plan)


@app.route('/api/payment/student/<int:sid>/edit', methods=['POST'])
@login_required
def api_payment_student_edit(sid):
    """Replace the recorded paid amount for a single installment.
    Body: {n, new_amount, reason}.
    Validates new_amount in [0, plan_amount], rewrites payment_log
    inst<N> + msg<N>, recomputes total_paid / total_remaining, mirrors
    to student_payments, and writes an audit row to payment_edits."""
    d = request.get_json() or {}
    try:
        n = int(d.get('n') or 0)
    except Exception:
        n = 0
    new_amount = _payment_to_float(d.get('new_amount'))
    reason = (d.get('reason') or '').strip()
    if n < 1 or n > 12:
        return jsonify({"ok": False, "error": "رقم القسط غير صحيح"}), 400
    if new_amount < 0:
        return jsonify({"ok": False, "error": "المبلغ لا يمكن أن يكون سالباً"}), 400
    db = get_db()
    plan = _payment_compute_plan(db, sid)
    if plan is None:
        return jsonify({"ok": False, "error": "الطالب غير موجود"}), 404
    target = None
    for inst in plan["plan"]["installments"]:
        if inst["n"] == n: target = inst; break
    if target is None:
        return jsonify({"ok": False, "error": "القسط غير موجود في خطة الطالب"}), 400
    if new_amount > target["amount"] + 0.005:
        return jsonify({
            "ok": False,
            "error": "المبلغ لا يمكن أن يتجاوز المبلغ المستحق " + str(target["amount"]) + " دينار",
            "max_amount": target["amount"],
        }), 400
    old_amount = float(target.get("paid") or 0)
    course_amount_now = plan["plan"]["course_amount"]
    student = plan["student"]
    pid     = (student.get('personal_id') or '').strip()
    sname   = (student.get('name') or '').strip()
    # Write to payment_log inst<N> + msg<N>. msg<N> = 'تم الدفع' if
    # new_amount > 0, else cleared (so the per-receipt dropdown
    # surfaces it again as still-owed).
    if n <= 5:
        try:
            paid_str = ('%g' % new_amount) if new_amount == int(new_amount) else str(new_amount)
            inst_col = 'inst' + str(n)
            msg_col  = 'msg'  + str(n)
            try:
                live_cols = {r[1] for r in db.execute("PRAGMA table_info(payment_log)").fetchall()}
            except Exception:
                live_cols = set()
            has_msg    = msg_col in live_cols
            has_total  = 'total_paid' in live_cols and 'total_remaining' in live_cols
            has_amount = 'course_amount' in live_cols
            row_id = None
            if pid:
                r = db.execute("SELECT id FROM payment_log WHERE personal_id=? AND personal_id <> '' LIMIT 1", (pid,)).fetchone()
                if r: row_id = r[0]
            if row_id is None and sname:
                r = db.execute("SELECT id FROM payment_log WHERE TRIM(student_name)=? LIMIT 1", (sname,)).fetchone()
                if r: row_id = r[0]
            if row_id is None and sname:
                r = db.execute("SELECT id FROM payment_log WHERE student_name ILIKE ? LIMIT 1", ('%' + sname + '%',)).fetchone()
                if r: row_id = r[0]
            new_msg = 'تم الدفع' if new_amount > 0.005 else ''
            if row_id is None:
                cols_  = ['student_name', inst_col]
                vals_  = [sname, paid_str if new_amount > 0 else '']
                if pid: cols_.insert(0, 'personal_id'); vals_.insert(0, pid)
                if has_msg:    cols_.append(msg_col);          vals_.append(new_msg)
                if has_amount and course_amount_now: cols_.append('course_amount'); vals_.append(course_amount_now)
                if has_total:  cols_ += ['total_paid', 'total_remaining']; vals_ += [new_amount, max(0.0, (course_amount_now or 0) - new_amount)]
                ph = ','.join(['?'] * len(vals_))
                db.execute(
                    'INSERT INTO payment_log(' + ','.join('"' + c + '"' for c in cols_) + ') VALUES(' + ph + ')',
                    tuple(vals_),
                )
                row_id = db.execute("SELECT MAX(id) FROM payment_log").fetchone()[0]
            else:
                set_pairs = ['"' + inst_col + '"=?']; params = [paid_str if new_amount > 0 else '']
                if has_msg:    set_pairs.append('"' + msg_col + '"=?');    params.append(new_msg)
                params.append(row_id)
                db.execute('UPDATE payment_log SET ' + ', '.join(set_pairs) + ' WHERE id=?', tuple(params))
            if has_total:
                fresh = db.execute(
                    'SELECT inst1,inst2,inst3,inst4,inst5 FROM payment_log WHERE id=?', (row_id,),
                ).fetchone()
                fresh_total = 0.0
                for k in range(1, 6):
                    cell = fresh[k - 1]
                    if cell is None: continue
                    s = str(cell).strip()
                    if not s: continue
                    if 'تم الدفع' in s or 'معفي' in s or 'معفى' in s:
                        plan_amt = 0.0
                        if k == n: plan_amt = new_amount
                        else:
                            for inst in plan["plan"]["installments"]:
                                if inst["n"] == k: plan_amt = inst["amount"]; break
                        fresh_total += plan_amt
                    else:
                        fresh_total += _payment_to_float(s)
                fresh_remaining = max(0.0, (course_amount_now or 0) - fresh_total)
                db.execute('UPDATE payment_log SET total_paid=?, total_remaining=? WHERE id=?',
                           (fresh_total, fresh_remaining, row_id))
            db.commit()
        except Exception as ex:
            return jsonify({"ok": False, "error": "payment_log write failed: " + str(ex)}), 500
    # Mirror to student_payments.
    try:
        db.execute(
            """INSERT INTO student_payments(student_id, inst_num, inst_type, price, paid)
               VALUES(?,?,?,?,?)
               ON CONFLICT(student_id, inst_num)
                 DO UPDATE SET paid=EXCLUDED.paid, price=EXCLUDED.price""",
            (sid, n, str(n), target["amount"], new_amount),
        )
    except Exception: pass
    # Audit log.
    user = session.get('user') or {}
    try:
        db.execute(
            "INSERT INTO payment_edits(student_id, student_name, personal_id, "
            "installment_number, old_amount, new_amount, reason, edited_by) "
            "VALUES(?,?,?,?,?,?,?,?)",
            (sid, sname, pid, n, old_amount, new_amount, reason,
             user.get('username') or 'admin'),
        )
        db.commit()
    except Exception: pass
    new_plan = _payment_compute_plan(db, sid)
    new_plan["ok"] = True
    new_plan["edited"] = {"n": n, "old_amount": old_amount, "new_amount": new_amount}
    return jsonify(new_plan)


@app.route('/api/payment-messages', methods=['POST'])
@login_required
def api_payment_messages_add():
    """Log a payment-reminder send. Body:
       {student_id?, student_name, installment_number, message_type?}.
       sent_by is auto-filled from the session user."""
    d = request.get_json() or {}
    user = session.get('user') or {}
    try:
        sid = int(d.get('student_id') or 0) or None
    except Exception:
        sid = None
    try:
        n = int(d.get('installment_number') or 0) or None
    except Exception:
        n = None
    sname = (d.get('student_name') or '').strip()
    mtype = (d.get('message_type') or 'due_reminder').strip()
    sender = (user.get('username') or 'admin').strip()
    db = get_db()
    try:
        db.execute(
            "INSERT INTO payment_messages(student_id, student_name, "
            "installment_number, message_type, sent_by) VALUES(?,?,?,?,?)",
            (sid, sname, n, mtype, sender),
        )
        db.commit()
        new_id = db.execute("SELECT last_insert_rowid()").fetchone()[0]
        return jsonify({"ok": True, "id": new_id})
    except Exception as ex:
        return jsonify({"ok": False, "error": str(ex)}), 400


@app.route('/api/payment-messages', methods=['GET'])
@login_required
def api_payment_messages_list():
    """List recent payment-reminder sends. Optional filter by student_id.
       Returns newest first, capped at 500 rows."""
    db = get_db()
