def _pts_weekly_series_for_student(db, sid, weeks=8):
    """8-week (configurable) positive/negative series for a single
    student. Same rolling-7-day windows the parent portal uses, hoisted
    here so the student portal can reuse it without duplicating code."""
    import datetime as _dt
    now = _dt.datetime.now()
    out = []
    for i in range(weeks - 1, -1, -1):
        wstart = (now - _dt.timedelta(days=(i + 1) * 7)).strftime("%Y-%m-%d %H:%M:%S")
        wend   = (now - _dt.timedelta(days=i * 7)).strftime("%Y-%m-%d %H:%M:%S")
        try:
            pos = db.execute(
                "SELECT COALESCE(SUM(points_value),0) FROM point_events "
                "WHERE student_id=? AND awarded_at>=? AND awarded_at<? AND points_value > 0",
                (sid, wstart, wend),
            ).fetchone()[0] or 0
            neg = db.execute(
                "SELECT COALESCE(SUM(points_value),0) FROM point_events "
                "WHERE student_id=? AND awarded_at>=? AND awarded_at<? AND points_value < 0",
                (sid, wstart, wend),
            ).fetchone()[0] or 0
        except Exception:
            pos = 0; neg = 0
        out.append({"week_end": wend[:10], "positive": int(pos), "negative": int(neg)})
    return out


def _pts_weekly_summary_for_student(db, sid):
    """Single-window summary for the last 7 days: positive sum,
    negative sum (returned as a negative integer), counts per polarity,
    net delta. Used by the student portal's "ملخص هذا الأسبوع" block."""
    import datetime as _dt
    since = (_dt.datetime.now() - _dt.timedelta(days=7)).strftime("%Y-%m-%d %H:%M:%S")
    try:
        pos = db.execute(
            "SELECT COALESCE(SUM(points_value),0), COUNT(*) FROM point_events "
            "WHERE student_id=? AND awarded_at>=? AND points_value > 0",
            (sid, since),
        ).fetchone()
        neg = db.execute(
            "SELECT COALESCE(SUM(points_value),0), COUNT(*) FROM point_events "
            "WHERE student_id=? AND awarded_at>=? AND points_value < 0",
            (sid, since),
        ).fetchone()
        pos_sum, pos_n = int(pos[0] or 0), int(pos[1] or 0)
        neg_sum, neg_n = int(neg[0] or 0), int(neg[1] or 0)
    except Exception:
        pos_sum = pos_n = neg_sum = neg_n = 0
    return {
        "positive":       pos_sum,
        "positive_count": pos_n,
        "negative":       neg_sum,    # negative integer or 0
        "negative_count": neg_n,
        "net":            pos_sum + neg_sum,
        "since":          since[:10],
    }


def _pts_group_meta_for_student(db, sd):
    """Resolve group display name + assigned teacher for one student."""
    gn = (sd.get("group_name_student") or "").strip()
    if not gn:
        return {"group_name": "", "teacher_name": ""}
    try:
        grow = db.execute(
            "SELECT group_name, teacher_name FROM student_groups "
            "WHERE TRIM(group_name)=TRIM(?) LIMIT 1",
            (gn,),
        ).fetchone()
    except Exception:
        grow = None
    if not grow:
        return {"group_name": gn, "teacher_name": ""}
    gd = dict(grow)
    return {
        "group_name":   (gd.get("group_name")   or gn).strip(),
        "teacher_name": (gd.get("teacher_name") or "").strip(),
    }


@app.route('/api/portal/student/me', methods=['GET'])
@login_required
def api_portal_student_me():
    """Returns everything the student portal needs in one round-trip:
    student record, group + teacher meta, balance, level + next level,
    avatar, the last 15 point events, weekly summary (last 7 days),
    and an 8-week positive/negative series for the chart.

    Ownership: forced to session.user.linked_student_id — there is no
    way to ask for another student's data via this endpoint."""
    user = session.get("user") or {}
    if (user.get("role") or "").strip().lower() != "student":
        return jsonify({"ok": False, "error": "forbidden"}), 403
    sid = int(user.get("linked_student_id") or 0)
    if not sid:
        return jsonify({"ok": False, "error": "account not linked to a student"}), 400
    db = get_db()
    try:
        srow = db.execute(
            "SELECT id, student_name, personal_id, group_name_student, avatar_id "
            "FROM students WHERE id=?", (sid,),
        ).fetchone()
    except Exception:
        srow = None
    if not srow:
        return jsonify({"ok": False, "error": "student record missing"}), 404
    sd = dict(srow)
    bal = _pts_balance(db, sid)
    lvl = _pts_level_for(db, bal)
    next_lvl = {}
    try:
        levels = db.execute(
            "SELECT id, name_ar, min_points, max_points, badge_icon, color "
            "FROM levels ORDER BY sort_order, min_points"
        ).fetchall()
        all_lvls = [dict(r) for r in levels]
        for L in all_lvls:
            if (L.get("min_points") or 0) > bal:
                next_lvl = L; break
    except Exception:
        all_lvls = []
    av = _pts_resolve_avatar(db, sd.get("avatar_id"))
    events  = _pts_recent_events(db, sid, 15)
    weekly  = _pts_weekly_series_for_student(db, sid, weeks=8)
    summary = _pts_weekly_summary_for_student(db, sid)
    grp_meta = _pts_group_meta_for_student(db, sd)
    return jsonify({
        "ok":              True,
        "student":         sd,
        "group_name":      grp_meta["group_name"],
        "teacher_name":    grp_meta["teacher_name"],
        "balance":         bal,
        "level":           lvl,
        "next_level":      next_lvl,
        "avatar":          av,
        "events":          events,
        "weekly_summary":  summary,
        "weekly":          weekly,
    })


@app.route('/api/portal/student/redemptions', methods=['GET'])
@login_required
def api_portal_student_redemptions():
    user = session.get("user") or {}
    if (user.get("role") or "").strip().lower() != "student":
        return jsonify({"ok": False, "error": "forbidden"}), 403
    sid = int(user.get("linked_student_id") or 0)
    if not sid:
        return jsonify({"ok": True, "rows": []})
    db = get_db()
    try:
        rows = db.execute(
            "SELECT id, reward_id, reward_name, points_spent, status, "
            "       redeemed_at, delivered_at "
            "FROM redemptions WHERE student_id=? ORDER BY id DESC LIMIT 50",
            (sid,),
        ).fetchall()
        return jsonify({"ok": True, "rows": [dict(r) for r in rows]})
    except Exception as ex:
        return jsonify({"ok": False, "error": str(ex)}), 500


# ── Unified parent-hub portal ────────────────────────────────────
# Parents log in with their child's personal ID. The hub at
# /portal/parent-hub is their landing page; three sub-pages
# (payments / attendance / points) are scoped to the logged-in
# student's id so URL tampering can never expose another child.
# The dedicated parent-account portal at /portal/parent (V2,
# multi-child) is unaffected.
def _ph_require_student():
    """Returns (user, student_id) for a logged-in role=student session,
    or a (None, error_response) tuple for any other state. Centralises
    ownership enforcement for every parent-hub route + API."""
    user = session.get("user") or {}
    if (user.get("role") or "").strip().lower() != "student":
        return None, (jsonify({"ok": False, "error": "forbidden"}), 403)
    sid = int(user.get("linked_student_id") or 0)
    if not sid:
        return None, (jsonify({"ok": False, "error": "account not linked to a student"}), 400)
    return (user, sid), None


def _ph_resolve_student_meta(db, sid):
    """Return {student, group_name, teacher_name, avatar} for the
    landing page header. Reuses the student-portal helpers so the
    hub and the points sub-page show identical metadata."""
    try:
        srow = db.execute(
            "SELECT id, student_name, personal_id, group_name_student, avatar_id "
            "FROM students WHERE id=?", (sid,),
        ).fetchone()
    except Exception:
        srow = None
    if not srow:
        return None
    sd = dict(srow)
    grp = _pts_group_meta_for_student(db, sd)
    av  = _pts_resolve_avatar(db, sd.get("avatar_id"))
    return {
        "student":      sd,
        "group_name":   grp["group_name"],
        "teacher_name": grp["teacher_name"],
        "avatar":       av,
    }


@app.route('/api/portal/student/meta', methods=['GET'])
@login_required
def api_portal_student_meta():
    """Header data for the parent-hub landing page + sub-pages."""
    pair, err = _ph_require_student()
    if err: return err
    _user, sid = pair
    db = get_db()
    meta = _ph_resolve_student_meta(db, sid)
    if not meta:
        return jsonify({"ok": False, "error": "student record missing"}), 404
    return jsonify({"ok": True, **meta})


@app.route('/api/portal/student/payments', methods=['GET'])
@login_required
def api_portal_student_payments():
    """Read-only payment plan + per-installment status for the
    logged-in student. Reuses _payment_compute_plan +
    _payment_log_paid_for_student so the numbers match what admin
    sees in /database and the search profile."""
    pair, err = _ph_require_student()
    if err: return err
    _user, sid = pair
    db = get_db()
    try:
        srow = db.execute(
            "SELECT id, student_name, personal_id, installment_type "
            "FROM students WHERE id=?", (sid,),
        ).fetchone()
    except Exception:
        srow = None
    if not srow:
        return jsonify({"ok": False, "error": "student record missing"}), 404
    sd = dict(srow)
    try:
        plan_payload = _payment_compute_plan(db, sd["id"])
    except Exception as ex:
        return jsonify({"ok": False, "error": str(ex)}), 500
    if plan_payload is None:
        return jsonify({"ok": False, "error": "could not compute plan"}), 500
    insts = [i for i in plan_payload["plan"]["installments"]
             if (i.get("amount") or 0) > 0]
    paid_pl, pl_dict = _payment_log_paid_for_student(
        db, sd.get("student_name"), sd.get("personal_id")
    )
    plan = plan_payload["plan"]
    paid_count = sum(1 for i in insts if (i.get("paid") or 0) > 0)
    return jsonify({
        "ok": True,
        "student": {
            "id":   sd["id"],
            "name": sd.get("student_name"),
        },
        "plan": {
            "method":           plan.get("method"),
            "course_amount":    plan.get("course_amount"),
            "num_installments": plan.get("num_installments"),
            "total_paid":       plan.get("total_paid"),
            "total_remaining":  plan.get("total_remaining"),
            "status":           plan.get("status"),
        },
        "summary": {
            "course_amount":   plan.get("course_amount") or 0,
            "total_paid":      plan.get("total_paid") or 0,
            "total_remaining": plan.get("total_remaining") or 0,
            "num_installments":  plan.get("num_installments") or 0,
            "paid_installments": paid_count,
            "remaining_installments": max(0, (plan.get("num_installments") or 0) - paid_count),
        },
        "installments": insts,
        "payments":     pl_dict or {},
    })


@app.route('/api/portal/student/attendance', methods=['GET'])
@login_required
def api_portal_student_attendance():
    """Attendance summary + log (last N rows) for the logged-in
    student. Read-only; no path param so URL tampering is impossible."""
    pair, err = _ph_require_student()
    if err: return err
    _user, sid = pair
    try:
        limit = max(1, min(int(request.args.get("limit") or 50), 200))
    except Exception:
        limit = 50
    db = get_db()
    try:
        srow = db.execute(
            "SELECT id, student_name, personal_id FROM students WHERE id=?", (sid,),
        ).fetchone()
    except Exception:
        srow = None
    if not srow:
        return jsonify({"ok": False, "error": "student record missing"}), 404
    sd = dict(srow)
    name = (sd.get("student_name") or "").strip()
    # Pull every row keyed by student_name (legacy data has no FK to
    # student_id). Filter Python-side so whitespace/normalisation
    # quirks the existing _att_normalize_date helper handles cleanly.
    try:
        rows = db.execute(
            "SELECT id, attendance_date, group_name, student_name, status, "
            "       day_name, message, message_status "
            "FROM attendance WHERE TRIM(student_name)=TRIM(?)",
            (name,),
        ).fetchall()
    except Exception as ex:
        return jsonify({"ok": False, "error": str(ex)}), 500
    STATUS_PRESENT = "حاضر"
    STATUS_ABSENT  = "غائب"
    STATUS_LATE    = "متأخر"
    out = []
    sessions = set()
    n_present = n_absent = n_late = 0
    for r in rows:
        rd = dict(r)
        d  = _att_normalize_date(rd.get("attendance_date"))
        g  = (rd.get("group_name") or "").strip()
        st = (rd.get("status") or "").strip()
        if d and g:
            sessions.add((d, g))
        if   st == STATUS_PRESENT: n_present += 1
        elif st == STATUS_ABSENT:  n_absent  += 1
        elif st == STATUS_LATE:    n_late    += 1
        out.append({
            "id":              rd.get("id"),
            "attendance_date": d,
            "day_name":        rd.get("day_name") or "",
            "group_name":      g,
            "status":          st,
            "message":         rd.get("message") or "",
        })
    out.sort(key=lambda x: (x.get("attendance_date") or ""), reverse=True)
    out = out[:limit]
    total = len(sessions)
    pct = round((n_present + n_late) / total * 100, 1) if total else 0.0
    return jsonify({
        "ok": True,
        "student": {"id": sd["id"], "name": name},
        "summary": {
            "present": n_present,
            "absent":  n_absent,
            "late":    n_late,
            "total":   total,
            "percent": pct,
        },
        "rows":  out,
    })


